// =============================================================================
// HPC CUDA Optimizer Library — Combined ZeRO-3 + Tensor Parallel Training Demo
// examples/train_zero3_tp.cu
//
// Demonstrates a realistic multi-GPU training loop that combines:
//   • ZeRO-3 parameter + optimizer state sharding  (hpc_zero3.cuh)
//   • Megatron-LM Tensor Parallelism for FFN/Attention (hpc_tensor_parallel.cuh)
//   • Mixed-precision BF16 forward, FP32 master weights
//   • WarmupCosine learning-rate schedule
//   • Gradient clipping on sharded gradients
//   • Checkpoint save every N steps
//
// Model:  GPT-style transformer (simplified, compute-focused)
//   Config:  hidden=2048, ffn=8192, heads=16, layers=24
//   Params:  ~1.3B (before TP sharding across T ranks)
//   Sequence length: 2048 tokens
//   Batch: 4 sequences per DP rank
//
// Parallelism layout:
//   Total GPU count = DP × TP
//   e.g. 32 GPUs: DP=4, TP=8  →  each TP group of 8 shares one layer
//                                  ZeRO-3 shards across 4 DP replicas
//
// Launch:
//   torchrun --nproc_per_node=8 train_zero3_tp.cu   [not Python — see note]
//   mpirun -np 8 ./train_zero3_tp
//
// Single-GPU stub (no NCCL): runs on rank 0 / world 1, stubs comms
//   nvcc -std=c++17 -O2 -I../include \
//        -gencode arch=compute_80,code=sm_80 \
//        train_zero3_tp.cu -o train_zero3_tp && ./train_zero3_tp
//
// Multi-GPU build:
//   nvcc -std=c++17 -O2 -DHPC_HAVE_NCCL -DHPC_HAVE_MPI -I../include \
//        -gencode arch=compute_80,code=sm_80 \
//        train_zero3_tp.cu -lnccl -lmpi -lcublas -o train_zero3_tp
// =============================================================================

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cuda_fp16.h>

#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>
#include <chrono>
#include <cassert>

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include "hpc_comm.cuh"
#include "hpc_lr_scheduler.cuh"
#include "hpc_optimizer.cuh"
#include "hpc_profiler.cuh"
#include "hpc_zero2.cuh"
#include "hpc_zero2_optimizer.cuh"
#include "hpc_zero3.cuh"
#include "hpc_tensor_parallel.cuh"

using namespace hpc_opt;
using namespace hpc_opt::zero2;
using namespace hpc_opt::zero3;
using namespace hpc_opt::tp;

// ============================================================================
// Configuration
// ============================================================================
struct ModelConfig {
    int hidden_dim  = 2048;
    int ffn_dim     = 8192;
    int n_heads     = 16;
    int n_layers    = 24;
    int vocab_size  = 32000;
    int max_seq_len = 2048;
};

struct TrainConfig {
    int    batch_size      = 4;       // sequences per DP rank
    int    total_steps     = 1000;
    int    warmup_steps    = 100;
    float  lr_max          = 3e-4f;
    float  lr_min          = 1e-5f;
    float  beta1           = 0.9f;
    float  beta2           = 0.95f;
    float  eps             = 1e-8f;
    float  weight_decay    = 0.1f;
    float  max_grad_norm   = 1.0f;
    int    ckpt_interval   = 200;
    int    log_interval    = 10;
    bool   fp16            = false;
    bool   bf16            = true;    // default: BF16 activations, FP32 master
    int    tp_size         = 1;       // tensor parallelism degree
    const char* ckpt_dir   = "/tmp/hpc_zero3_ckpts";
};

// ============================================================================
// Print banner
// ============================================================================
static void print_banner(const ModelConfig& mc, const TrainConfig& tc,
                         int rank, int world, int dp_size)
{
    if (rank != 0) return;

    auto param_count = [&]() -> size_t {
        // Embedding:        vocab * H
        // LayerNorm (each): 2H
        // Attention QKV:    H * 3H
        // Attention out:    H * H
        // FFN fc1:          H * ffn
        // FFN fc2:          ffn * H
        // Final LN + LM head: H * vocab
        size_t emb  = (size_t)mc.vocab_size * mc.hidden_dim;
        size_t attn = (size_t)mc.n_layers * (3ULL*mc.hidden_dim*mc.hidden_dim
                                              + mc.hidden_dim*mc.hidden_dim);
        size_t ffn  = (size_t)mc.n_layers * 2ULL * mc.hidden_dim * mc.ffn_dim;
        size_t ln   = (size_t)(mc.n_layers * 2 + 1) * 2 * mc.hidden_dim;
        size_t head = (size_t)mc.hidden_dim * mc.vocab_size;
        return emb + attn + ffn + ln + head;
    };

    size_t total_params = param_count();
    size_t param_bytes  = total_params * 16;  // ZeRO-0: 16 bytes/param
    size_t z3_bytes     = param_bytes / world; // ZeRO-3: /world_size

    printf("\n");
    printf("╔══════════════════════════════════════════════════════════════╗\n");
    printf("║        HPC Optimizer — ZeRO-3 + Tensor Parallel Demo        ║\n");
    printf("╚══════════════════════════════════════════════════════════════╝\n");
    printf("  Model\n");
    printf("    Hidden dim     : %d\n",  mc.hidden_dim);
    printf("    FFN dim        : %d\n",  mc.ffn_dim);
    printf("    Attention heads: %d\n",  mc.n_heads);
    printf("    Layers         : %d\n",  mc.n_layers);
    printf("    Vocab size     : %d\n",  mc.vocab_size);
    printf("    Seq length     : %d\n",  mc.max_seq_len);
    printf("    ~Parameters    : %.2fB\n", total_params / 1e9);
    printf("  Training\n");
    printf("    Batch / DP rank: %d seqs\n", tc.batch_size);
    printf("    Steps          : %d  (warmup %d)\n",
           tc.total_steps, tc.warmup_steps);
    printf("    LR             : %.2e → %.2e (WarmupCosine)\n",
           tc.lr_max, tc.lr_min);
    printf("    Grad clip norm : %.1f\n",     tc.max_grad_norm);
    printf("    Precision      : %s\n",
           tc.bf16 ? "BF16 fwd/bwd + FP32 master" : "FP32");
    printf("  Parallelism\n");
    printf("    World size     : %d GPUs\n", world);
    printf("    DP size        : %d\n", dp_size);
    printf("    TP size        : %d\n", tc.tp_size);
    printf("  Memory (estimated, per DP rank)\n");
    printf("    ZeRO-0         : %.1f GB\n", param_bytes / 1e9);
    printf("    ZeRO-3         : %.1f GB   (%.1f× saving vs ZeRO-0)\n",
           z3_bytes / 1e9, (float)world);
    printf("──────────────────────────────────────────────────────────────\n\n");
}

// ============================================================================
// Synthetic data generator
//   Produces random token IDs [batch, seq_len] on device
// ============================================================================
__global__ void k_random_tokens(int32_t* __restrict__ tokens,
                                 size_t n, int vocab_size, uint64_t seed)
{
    size_t i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= n) return;
    // LCG random
    uint64_t v = seed ^ (i * 6364136223846793005ULL + 1442695040888963407ULL);
    v ^= v >> 33; v *= 0xff51afd7ed558ccdULL;
    v ^= v >> 33; v *= 0xc4ceb9fe1a85ec53ULL;
    v ^= v >> 33;
    tokens[i] = (int32_t)((uint32_t)v % (uint32_t)vocab_size);
}

// ============================================================================
// Minimal transformer layer (compute-placeholder)
//
// In a full implementation each layer would be:
//   LN → ColParallel(QKV) → Attention → RowParallel(Out)
//              ↓
//   LN → ColParallel(FC1) → GELU → RowParallel(FC2)
//
// Here we demonstrate the full wiring with the library structs.
// Actual backward passes would use autograd or hand-written CUDA;
// for this demo we synthesize gradients proportional to activations.
// ============================================================================
struct TransformerLayer {
    SequenceParallelLayerNorm ln1, ln2;
    ColumnParallelLinear       qkv_proj;   // ColParallel: H → 3H/T
    RowParallelLinear          out_proj;   // RowParallel: H/T → H
    ColumnParallelLinear       fc1;        // ColParallel: H → 4H/T
    RowParallelLinear          fc2;        // RowParallel: 4H/T → H

    void init(const ModelConfig& mc, int tp_rank, int tp_sz, Dtype dt,
              size_t max_tok)
    {
        int H   = mc.hidden_dim;
        int ffn = mc.ffn_dim;

        ln1.init(H, dt, 1e-5f, max_tok);
        ln2.init(H, dt, 1e-5f, max_tok);

        // QKV: input H → output 3H (col parallel → each rank gets 3H/T)
        qkv_proj.init(H, 3*H, tp_rank, tp_sz,
                      /*gather=*/false, /*bias=*/true, dt, max_tok);
        // Out: input H/T (from QKV shard) → output H (row parallel)
        out_proj.init(H, H, tp_rank, tp_sz,
                      /*bias=*/true, dt, max_tok);
        // FFN
        fc1.init(H, ffn, tp_rank, tp_sz, false, true, dt, max_tok);
        fc2.init(ffn, H, tp_rank, tp_sz, true,  dt, max_tok);
    }

    // Returns: [tokens, H]  (same shape as input)
    void* forward(const TPContext& tpc, const void* x, int tokens,
                  cudaStream_t cs)
    {
        // Attention sub-layer (simplified: skip actual softmax attention)
        void* ln1_out = ln1.forward(x, tokens, cs);
        // QKV projection → [tokens, 3H/T]
        void* qkv     = qkv_proj.forward(tpc, ln1_out, tokens, cs);
        // In a full impl: reshape QKV, compute scaled dot-product attention...
        // Out projection: take first H/T slice as mock "attention output"
        void* attn_out = out_proj.forward(tpc, qkv, tokens, cs);
        // (Residual add would go here — omitted for brevity)

        // FFN sub-layer
        void* ln2_out  = ln2.forward(attn_out, tokens, cs);
        void* fc1_out  = fc1.forward(tpc, ln2_out, tokens, cs);
        // GELU inplace on fc1_out [tokens, ffn/T]
        size_t ffn_local = fc1.local_out;
        k_gelu_inplace<__nv_bfloat16><<<
            hpc_blocks((size_t)tokens * ffn_local), HPC_BLOCK, 0, cs>>>(
            static_cast<__nv_bfloat16*>(fc1_out),
            (size_t)tokens * ffn_local);
        void* fc2_out  = fc2.forward(tpc, fc1_out, tokens, cs);
        return fc2_out;
    }

    size_t total_params_per_layer(const ModelConfig& mc, int tp_sz) const {
        int H = mc.hidden_dim, ffn = mc.ffn_dim;
        // QKV weight: H * 3H/T, Out weight: H/T * H, FC1: H * ffn/T, FC2: ffn/T * H
        // Plus biases (small)
        return (size_t)(H*(3*H/tp_sz) + (H/tp_sz)*H
                      + H*(ffn/tp_sz) + (ffn/tp_sz)*H);
    }

    void destroy() {
        ln1.destroy(); ln2.destroy();
        qkv_proj.destroy(); out_proj.destroy();
        fc1.destroy(); fc2.destroy();
    }
};

// ============================================================================
// Synthetic "loss" and gradient computation
//   loss = mean(||output - target||^2) / 2
//   dloss/doutput = (output - target) / N
// ============================================================================
__global__ void k_synthetic_loss(
        const __nv_bfloat16* __restrict__ output,
        const __nv_bfloat16* __restrict__ target,
        float* __restrict__ loss_out,
        size_t N)
{
    __shared__ float sdata[HPC_BLOCK];
    float sum = 0.f;
    for (size_t i = blockIdx.x*blockDim.x+threadIdx.x; i < N;
         i += gridDim.x*blockDim.x) {
        float diff = __bfloat162float(output[i]) - __bfloat162float(target[i]);
        sum += diff * diff;
    }
    sdata[threadIdx.x] = sum;
    __syncthreads();
    for (int s = blockDim.x/2; s > 0; s >>= 1) {
        if (threadIdx.x < (size_t)s) sdata[threadIdx.x] += sdata[threadIdx.x+s];
        __syncthreads();
    }
    if (threadIdx.x == 0) atomicAdd(loss_out, sdata[0] / (2.0f * N));
}

__global__ void k_compute_grad(
        const __nv_bfloat16* __restrict__ output,
        const __nv_bfloat16* __restrict__ target,
        float* __restrict__ grad,
        size_t N)
{
    for (size_t i = blockIdx.x*blockDim.x+threadIdx.x; i < N;
         i += gridDim.x*blockDim.x)
        grad[i] = (__bfloat162float(output[i])
                 - __bfloat162float(target[i])) / (float)N;
}

// ============================================================================
// ZeRO-3 + TP trainer
// ============================================================================
struct Zero3TPTrainer {
    // ZeRO-3 engine (DP sharding)
    ZeRO3Trainer zero3;

    // TP layers (replicated per DP rank, sharded across TP)
    std::vector<TransformerLayer> layers;
    VocabParallelEmbedding        embed;

    TPContext tp_ctx;

    ModelConfig mc;
    TrainConfig tc;

    int world, rank, dp_rank, dp_size;
    int tp_rank, tp_size_val;

    cudaStream_t compute_stream, comm_stream;

    // LR scheduler
    WarmupCosineScheduler* lr_sched = nullptr;

    // Profiler
    IterationProfiler* profiler = nullptr;

    void init(const ModelConfig& m, const TrainConfig& t,
              CommContext& comm)
    {
        mc   = m;
        tc   = t;
        rank  = comm.rank();
        world = comm.world_size();

        // Layout: TP contiguous, DP outer
        // rank = dp_rank * tp_size + tp_rank
        tp_size_val = tc.tp_size;
        tp_rank     = rank % tp_size_val;
        dp_rank     = rank / tp_size_val;
        dp_size     = world / tp_size_val;

        HPC_CUDA_CHECK(cudaStreamCreate(&compute_stream));
        HPC_CUDA_CHECK(cudaStreamCreate(&comm_stream));

        // Build TP context for this rank's TP group
        tp_ctx = TPContext::from_comm(comm, compute_stream, comm_stream);
        tp_ctx.tp_rank  = tp_rank;
        tp_ctx.tp_size  = tp_size_val;

        Dtype dt = tc.bf16 ? Dtype::BF16 :
                   tc.fp16 ? Dtype::FP16 : Dtype::FP32;

        size_t max_tok = (size_t)tc.batch_size * mc.max_seq_len;

        // Vocab embedding (TP-sharded)
        embed.init(mc.vocab_size, mc.hidden_dim,
                   tp_rank, tp_size_val, dt, max_tok);

        // Transformer layers
        layers.resize(mc.n_layers);
        for (int l = 0; l < mc.n_layers; ++l)
            layers[l].init(mc, tp_rank, tp_size_val, dt, max_tok);

        // ZeRO-3: shard embedding + layer weights across DP group
        // Compute total parameter count for this TP rank
        size_t local_params = (size_t)mc.hidden_dim * (mc.vocab_size / tp_size_val);  // embed
        for (int l = 0; l < mc.n_layers; ++l)
            local_params += layers[l].total_params_per_layer(mc, tp_size_val);

        ZeRO3TrainerConfig z3c;
        z3c.lr           = tc.lr_max;
        z3c.beta1        = tc.beta1;
        z3c.beta2        = tc.beta2;
        z3c.eps          = tc.eps;
        z3c.weight_decay = tc.weight_decay;
        z3c.max_grad_norm = tc.max_grad_norm;
        z3c.release_full_params_immediately = true;

        zero3.init(local_params, dp_rank, dp_size, z3c, comm,
                   compute_stream, comm_stream);

        // LR scheduler
        lr_sched = new WarmupCosineScheduler(
            tc.lr_max, tc.lr_min, tc.warmup_steps, tc.total_steps);

        // Profiler
        profiler = new IterationProfiler(rank == 0);

        if (rank == 0) {
            printf("[ZeRO-3+TP] Initialized:\n");
            printf("  TP rank %d/%d, DP rank %d/%d\n",
                   tp_rank, tp_size_val, dp_rank, dp_size);
            printf("  Local params (TP-sharded): %.2fM\n",
                   local_params / 1e6);
            zero3.engine.print_memory_stats(rank, dp_size);
        }
    }

    // -------------------------------------------------------------------------
    // One training step
    // -------------------------------------------------------------------------
    float step(int step_idx, int32_t* d_tokens)
    {
        float lr = lr_sched->get_lr(step_idx);
        zero3.trainer_config.lr = lr;

        int tokens = tc.batch_size * mc.max_seq_len;

        // ---- Forward pass ----
        profiler->start_forward();

        // Prefetch params from shards
        zero3.prefetch_params();

        // Embedding lookup
        void* hidden = embed.forward(tp_ctx, d_tokens, tokens, compute_stream);

        // Transformer layers
        for (int l = 0; l < mc.n_layers; ++l)
            hidden = layers[l].forward(tp_ctx, hidden, tokens, compute_stream);

        // Synthetic target = zeros (cross-entropy would go here)
        Dtype dt = tc.bf16 ? Dtype::BF16 : Dtype::FP32;
        size_t out_bytes = (size_t)tokens * mc.hidden_dim *
                           (dt == Dtype::FP32 ? 4 : 2);

        __nv_bfloat16 *d_target, *d_hidden_bf16;
        cudaMalloc(&d_target, out_bytes);
        cudaMemset(d_target, 0, out_bytes);
        d_hidden_bf16 = static_cast<__nv_bfloat16*>(hidden);

        // Compute loss
        float *d_loss;
        cudaMalloc(&d_loss, sizeof(float));
        cudaMemset(d_loss, 0, sizeof(float));
        k_synthetic_loss<<<hpc_blocks((size_t)tokens*mc.hidden_dim), HPC_BLOCK,
                           0, compute_stream>>>(
            d_hidden_bf16, d_target, d_loss,
            (size_t)tokens * mc.hidden_dim);

        float h_loss;
        cudaMemcpyAsync(&h_loss, d_loss, sizeof(float),
                        cudaMemcpyDeviceToHost, compute_stream);

        profiler->end_forward();

        // ---- Backward pass ----
        profiler->start_backward();

        // Release full params (ZeRO-3 memory saving)
        zero3.release_params();

        // Synthesize gradients (in a real system: autograd / custom bwd kernels)
        float *d_grad;
        cudaMalloc(&d_grad, (size_t)tokens * mc.hidden_dim * sizeof(float));
        // grad = (output - target) / N
        k_compute_grad<<<hpc_blocks((size_t)tokens*mc.hidden_dim), HPC_BLOCK,
                         0, compute_stream>>>(
            d_hidden_bf16, d_target, d_grad,
            (size_t)tokens * mc.hidden_dim);

        // ZeRO-3 backward: pack grads → ReduceScatter → clip → optimizer step
        // For this demo, we use the engine's grad bucket directly
        float *d_grad_bucket = zero3.engine.grad_flat;
        size_t shard_numel   = zero3.engine.layout.shard_size;

        // Copy our synthetic grad into the shard grad (scaled to shard size)
        size_t copy_n = std::min((size_t)tokens * mc.hidden_dim, shard_numel);
        cudaMemcpyAsync(d_grad_bucket, d_grad,
                        copy_n * sizeof(float),
                        cudaMemcpyDeviceToDevice, compute_stream);
        if (copy_n < shard_numel)
            cudaMemsetAsync(d_grad_bucket + copy_n, 0,
                            (shard_numel - copy_n) * sizeof(float),
                            compute_stream);

        zero3.backward_step(step_idx + 1);
        profiler->end_backward();

        // Synchronize and read loss
        cudaStreamSynchronize(compute_stream);
        cudaStreamSynchronize(comm_stream);

        cudaFree(d_target);
        cudaFree(d_loss);
        cudaFree(d_grad);

        return h_loss;
    }

    void save_checkpoint(int step_idx) {
        char path[512];
        snprintf(path, sizeof(path), "%s/step_%06d_dp%d_tp%d.bin",
                 tc.ckpt_dir, step_idx, dp_rank, tp_rank);
        zero3.save_checkpoint(path);
        if (rank == 0)
            printf("[CKPT] Saved checkpoint: %s\n", path);
    }

    void destroy() {
        for (auto& l : layers) l.destroy();
        embed.destroy();
        tp_ctx.destroy();
        delete lr_sched;
        delete profiler;
        cudaStreamDestroy(compute_stream);
        cudaStreamDestroy(comm_stream);
    }
};

// ============================================================================
// Main
// ============================================================================
int main(int argc, char** argv)
{
    // Parse optional CLI overrides
    ModelConfig mc;
    TrainConfig tc;

    for (int i = 1; i < argc; ++i) {
        if (strcmp(argv[i], "--layers")  == 0 && i+1 < argc) mc.n_layers    = atoi(argv[++i]);
        if (strcmp(argv[i], "--hidden")  == 0 && i+1 < argc) mc.hidden_dim  = atoi(argv[++i]);
        if (strcmp(argv[i], "--ffn")     == 0 && i+1 < argc) mc.ffn_dim     = atoi(argv[++i]);
        if (strcmp(argv[i], "--steps")   == 0 && i+1 < argc) tc.total_steps = atoi(argv[++i]);
        if (strcmp(argv[i], "--tp")      == 0 && i+1 < argc) tc.tp_size     = atoi(argv[++i]);
        if (strcmp(argv[i], "--batch")   == 0 && i+1 < argc) tc.batch_size  = atoi(argv[++i]);
        if (strcmp(argv[i], "--fp32")    == 0)  { tc.bf16 = false; tc.fp16 = false; }
        if (strcmp(argv[i], "--fp16")    == 0)  { tc.bf16 = false; tc.fp16 = true;  }
    }

#ifdef HPC_HAVE_MPI
    MPI_Init(&argc, &argv);
#endif

    // Initialize communicator
    CommContext comm;
    comm.init();
    int rank  = comm.rank();
    int world = comm.world_size();
    cudaSetDevice(rank % 8);  // up to 8 GPUs per node

    if (rank == 0) print_hpc_banner();

    int dp_size = world / tc.tp_size;
    print_banner(mc, tc, rank, world, dp_size);

    // ---- Initialize trainer ----
    Zero3TPTrainer trainer;
    trainer.init(mc, tc, comm);

    // ---- Synthetic data ----
    int total_tokens = tc.batch_size * mc.max_seq_len;
    int32_t *d_tokens;
    cudaMalloc(&d_tokens, total_tokens * sizeof(int32_t));

    // ---- Training loop ----
    auto t_start = std::chrono::high_resolution_clock::now();
    float running_loss = 0.f;

    if (rank == 0) {
        printf("%-8s %-10s %-10s %-12s %-14s\n",
               "Step", "Loss", "LR", "Tokens/s", "Time(ms)");
        printf("─────────────────────────────────────────────────────\n");
    }

    for (int step = 0; step < tc.total_steps; ++step) {
        // Generate synthetic batch
        k_random_tokens<<<hpc_blocks(total_tokens), HPC_BLOCK, 0, 0>>>(
            d_tokens, total_tokens, mc.vocab_size,
            (uint64_t)step * 1234567891ULL + rank);
        cudaDeviceSynchronize();

        auto t0 = std::chrono::high_resolution_clock::now();
        float loss = trainer.step(step, d_tokens);
        auto t1 = std::chrono::high_resolution_clock::now();

        running_loss = (step == 0) ? loss :
                       0.9f * running_loss + 0.1f * loss;

        if (rank == 0 && (step % tc.log_interval == 0 || step == tc.total_steps - 1)) {
            double ms = std::chrono::duration<double, std::milli>(t1 - t0).count();
            double total_s = std::chrono::duration<double>(t1 - t_start).count();
            double toks_s = total_tokens * world / (ms / 1e3);
            float  lr_now = trainer.lr_sched->get_lr(step);

            printf("%-8d %-10.4f %-10.2e %-12.0f %-14.1f\n",
                   step, running_loss, lr_now, toks_s, ms);
        }

        // Checkpoint
        if (tc.ckpt_interval > 0 && (step + 1) % tc.ckpt_interval == 0)
            trainer.save_checkpoint(step + 1);
    }

    if (rank == 0) {
        printf("─────────────────────────────────────────────────────\n");
        printf("Training complete. Final loss: %.4f\n\n", running_loss);

        // Memory summary
        size_t free_mem, total_mem;
        cudaMemGetInfo(&free_mem, &total_mem);
        printf("GPU memory: %.1f GB used / %.1f GB total\n",
               (total_mem - free_mem) / 1e9, total_mem / 1e9);
    }

    // ---- Memory comparison table ----
    if (rank == 0) {
        size_t psi       = 1'300'000'000ULL;  // approx model params
        size_t bytes_fp  = tc.bf16 ? 2 : 4;
        size_t z0_bytes  = 16ULL * psi;
        size_t z1_bytes  = (8 + 8/world) * psi;  // rough
        size_t z2_bytes  = (4 + 12/world) * psi;
        size_t z3_bytes  = 16ULL * psi / world;
        printf("\nMemory savings summary (1.3B params, %d GPUs):\n", world);
        printf("  %-12s  %6.1f GB  (baseline)\n", "ZeRO-0", z0_bytes / 1e9);
        printf("  %-12s  %6.1f GB  (%.1f×)\n",
               "ZeRO-1", z1_bytes / 1e9, (float)z0_bytes/z1_bytes);
        printf("  %-12s  %6.1f GB  (%.1f×)\n",
               "ZeRO-2", z2_bytes / 1e9, (float)z0_bytes/z2_bytes);
        printf("  %-12s  %6.1f GB  (%.1f×)  ← active\n",
               "ZeRO-3", z3_bytes / 1e9, (float)z0_bytes/z3_bytes);
    }

    // ---- Cleanup ----
    cudaFree(d_tokens);
    trainer.destroy();
    comm.destroy();

#ifdef HPC_HAVE_MPI
    MPI_Finalize();
#endif

    return 0;
}

include/hpc_adam.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_adam.cuh  –  Fused Adam / AdamW kernels
//
// HPC design choices:
//   • 512-thread blocks — saturates A100 (108 SMs × 64 warps)
//   • Vectorized 128-bit loads: float4 (FP32), half2 (FP16), bfloat162 (BF16)
//   • Master-weight FP32 buffer alongside FP16/BF16 params for stable accumulators
//   • __ldg() cache hints on read-only grad / moment buffers
//   • Fused weight-decay, bias correction, and param update in one kernel pass
//   • Optional stochastic rounding for FP16 storage (reduces quantization bias)
//   • AMSGrad variant keeps v_max for monotone step-size guarantee
//
// Targets: V100 (sm_70) | A100 (sm_80) | H100 (sm_90)
// =============================================================================
#pragma once

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include <cmath>
#include <memory>
#include <vector>

namespace hpc_opt {

// ---------------------------------------------------------------------------
// Fused Adam kernel – generic dtype for params & grads
//   Moments (m, v) are always FP32 for numerical stability.
//   master_fp32: if non-null, params is low-precision and this is the FP32 copy.
// ---------------------------------------------------------------------------
template<typename ParamT, typename GradT>
__global__ void k_adam(
        ParamT* __restrict__       params,
        float*  __restrict__       master_fp32,   // nullptr → pure FP32 path
        const GradT* __restrict__  grads,
        float*  __restrict__       m,
        float*  __restrict__       v,
        float*  __restrict__       v_max,         // nullptr if !amsgrad
        size_t  numel,
        float   lr_eff,     // lr * sqrt(1-β₂^t) / (1-β₁^t)
        float   lr,         // raw lr (needed for AdamW WD term)
        float   beta1,
        float   beta2,
        float   eps,
        float   weight_decay,
        bool    adamw,      // true → decoupled WD, false → L2-regularised
        bool    amsgrad)
{
    const size_t stride = gridDim.x * blockDim.x;
    size_t i = blockIdx.x * blockDim.x + threadIdx.x;

    for (; i < numel; i += stride) {
        // Load param (always via master if provided)
        float p = master_fp32 ? __ldg(master_fp32 + i)
                               : prec::to_float(__ldg(params + i));
        float g = prec::to_float(__ldg(grads + i));

        // NaN/Inf guard — skip bad gradient silently
        if (!prec::is_finite(g)) continue;

        // L2-style weight decay (Adam, not AdamW)
        if (!adamw && weight_decay != 0.0f) g += weight_decay * p;

        // Moment updates
        float mi = beta1 * __ldg(m + i) + (1.0f - beta1) * g;
        float vi = beta2 * __ldg(v + i) + (1.0f - beta2) * g * g;
        m[i] = mi;
        v[i] = vi;

        // Denominator
        float denom;
        if (amsgrad) {
            float vmax_i = fmaxf(__ldg(v_max + i), vi);
            v_max[i] = vmax_i;
            denom = sqrtf(vmax_i) + eps;
        } else {
            denom = sqrtf(vi) + eps;
        }

        // Parameter update
        p -= lr_eff * mi / denom;

        // Decoupled weight decay (AdamW)
        if (adamw && weight_decay != 0.0f) p -= lr * weight_decay * p;

        // Write back — update master first, then cast
        if (master_fp32) {
            master_fp32[i] = p;
            if constexpr (std::is_same_v<ParamT, half>)
                params[i] = __float2half(p);
            else  // bfloat16
                params[i] = __float2bfloat16(p);
        } else {
            params[i] = static_cast<float>(p);
        }
    }
}

// ---------------------------------------------------------------------------
// Vectorised FP32 Adam — 4 elements per thread via float4
// Dramatically reduces memory transactions on A100 HBM2e.
// ---------------------------------------------------------------------------
__global__ void k_adam_vec4_fp32(
        float* __restrict__       params,
        const float* __restrict__ grads,
        float* __restrict__       m,
        float* __restrict__       v,
        size_t  numel4,   // numel / 4
        float   lr_eff,
        float   lr,
        float   beta1,
        float   beta2,
        float   eps,
        float   weight_decay,
        bool    adamw)
{
    const size_t stride = gridDim.x * blockDim.x;
    size_t i4 = blockIdx.x * blockDim.x + threadIdx.x;

    for (; i4 < numel4; i4 += stride) {
        size_t base = i4 * 4;

        // 128-bit loads
        float4 p4 = *reinterpret_cast<const float4*>(params + base);
        float4 g4 = *reinterpret_cast<const float4*>(grads  + base);
        float4 m4 = *reinterpret_cast<const float4*>(m      + base);
        float4 v4 = *reinterpret_cast<const float4*>(v      + base);

        // Process lane 0
        if (!adamw) g4.x += weight_decay * p4.x;
        m4.x = beta1 * m4.x + (1.0f - beta1) * g4.x;
        v4.x = beta2 * v4.x + (1.0f - beta2) * g4.x * g4.x;
        p4.x -= lr_eff * m4.x / (sqrtf(v4.x) + eps);
        if (adamw && weight_decay != 0.0f) p4.x -= lr * weight_decay * p4.x;

        // Lane 1
        if (!adamw) g4.y += weight_decay * p4.y;
        m4.y = beta1 * m4.y + (1.0f - beta1) * g4.y;
        v4.y = beta2 * v4.y + (1.0f - beta2) * g4.y * g4.y;
        p4.y -= lr_eff * m4.y / (sqrtf(v4.y) + eps);
        if (adamw && weight_decay != 0.0f) p4.y -= lr * weight_decay * p4.y;

        // Lane 2
        if (!adamw) g4.z += weight_decay * p4.z;
        m4.z = beta1 * m4.z + (1.0f - beta1) * g4.z;
        v4.z = beta2 * v4.z + (1.0f - beta2) * g4.z * g4.z;
        p4.z -= lr_eff * m4.z / (sqrtf(v4.z) + eps);
        if (adamw && weight_decay != 0.0f) p4.z -= lr * weight_decay * p4.z;

        // Lane 3
        if (!adamw) g4.w += weight_decay * p4.w;
        m4.w = beta1 * m4.w + (1.0f - beta1) * g4.w;
        v4.w = beta2 * v4.w + (1.0f - beta2) * g4.w * g4.w;
        p4.w -= lr_eff * m4.w / (sqrtf(v4.w) + eps);
        if (adamw && weight_decay != 0.0f) p4.w -= lr * weight_decay * p4.w;

        // 128-bit stores
        *reinterpret_cast<float4*>(params + base) = p4;
        *reinterpret_cast<float4*>(m      + base) = m4;
        *reinterpret_cast<float4*>(v      + base) = v4;
    }
}

// ---------------------------------------------------------------------------
// Vectorised BF16 Adam — 2 elements per thread (Ampere+)
// ---------------------------------------------------------------------------
__global__ void k_adam_vec2_bf16(
        __nv_bfloat16* __restrict__       params,
        float*         __restrict__       master,
        const __nv_bfloat16* __restrict__ grads,
        float*         __restrict__       m,
        float*         __restrict__       v,
        size_t  numel2,
        float   lr_eff,
        float   lr,
        float   beta1,
        float   beta2,
        float   eps,
        float   weight_decay,
        bool    adamw)
{
    const size_t stride = gridDim.x * blockDim.x;
    size_t i2 = blockIdx.x * blockDim.x + threadIdx.x;

    for (; i2 < numel2; i2 += stride) {
        size_t base = i2 * 2;

        float g0, g1, p0, p1;
        prec::load2_bf16(grads,  base, g0, g1);

        p0 = master[base];
        p1 = master[base + 1];

        // Slot 0
        if (!adamw) g0 += weight_decay * p0;
        float m0 = beta1 * m[base]     + (1.0f - beta1) * g0;
        float v0 = beta2 * v[base]     + (1.0f - beta2) * g0 * g0;
        p0 -= lr_eff * m0 / (sqrtf(v0) + eps);
        if (adamw && weight_decay != 0.0f) p0 -= lr * weight_decay * p0;

        // Slot 1
        if (!adamw) g1 += weight_decay * p1;
        float m1 = beta1 * m[base + 1] + (1.0f - beta1) * g1;
        float v1 = beta2 * v[base + 1] + (1.0f - beta2) * g1 * g1;
        p1 -= lr_eff * m1 / (sqrtf(v1) + eps);
        if (adamw && weight_decay != 0.0f) p1 -= lr * weight_decay * p1;

        // Store
        m[base]     = m0; m[base + 1] = m1;
        v[base]     = v0; v[base + 1] = v1;
        master[base]     = p0; master[base + 1] = p1;
        prec::store2_bf16(params, base, p0, p1);
    }
}

// ===========================================================================
// AdamOptimizer  –  stateful HPC wrapper
// ===========================================================================
class AdamOptimizer {
public:
    explicit AdamOptimizer(const AdamConfig& cfg, bool adamw = false)
        : cfg_(cfg), adamw_(adamw) {}

    ~AdamOptimizer() { free_state(); }

    AdamOptimizer(const AdamOptimizer&)            = delete;
    AdamOptimizer& operator=(const AdamOptimizer&) = delete;

    // -----------------------------------------------------------------------
    // init  –  allocate moment buffers for all parameter tensors.
    //          master_fp32: caller-provided FP32 master weight buffers
    //          (one per tensor, same numel). Pass nullptr for pure FP32 training.
    // -----------------------------------------------------------------------
    void init(const TensorView* params, int n,
              float** master_fp32 = nullptr,
              cudaStream_t stream = 0)
    {
        free_state();
        n_tensors_   = n;
        master_fp32_ = master_fp32;
        m_           = new float*[n];
        v_           = new float*[n];
        v_max_       = cfg_.amsgrad ? new float*[n] : nullptr;

        for (int i = 0; i < n; ++i) {
            size_t bytes = params[i].numel * sizeof(float);
            HPC_CUDA_CHECK(cudaMalloc(&m_[i], bytes));
            HPC_CUDA_CHECK(cudaMalloc(&v_[i], bytes));
            HPC_CUDA_CHECK(cudaMemsetAsync(m_[i], 0, bytes, stream));
            HPC_CUDA_CHECK(cudaMemsetAsync(v_[i], 0, bytes, stream));
            if (cfg_.amsgrad) {
                HPC_CUDA_CHECK(cudaMalloc(&v_max_[i], bytes));
                HPC_CUDA_CHECK(cudaMemsetAsync(v_max_[i], 0, bytes, stream));
            }
        }
    }

    // -----------------------------------------------------------------------
    // step  –  one optimizer step, auto-dispatches to the best kernel path
    // -----------------------------------------------------------------------
    void step(TensorView* params, const TensorView* grads, int n,
              cudaStream_t stream = 0)
    {
        step_++;
        const float bc1    = 1.0f - powf(cfg_.beta1, (float)step_);
        const float bc2    = 1.0f - powf(cfg_.beta2, (float)step_);
        const float lr_eff = cfg_.lr * sqrtf(bc2) / bc1;

        for (int i = 0; i < n; ++i) {
            const size_t numel = params[i].numel;
            const int    blk   = hpc_blocks(numel);

            // ------ FP32 vectorised fast path (4-wide, no master needed) ------
            if (params[i].dtype == Dtype::FP32 &&
                grads[i].dtype  == Dtype::FP32 &&
                !cfg_.amsgrad   && (numel % 4 == 0))
            {
                k_adam_vec4_fp32<<<blk, HPC_BLOCK, 0, stream>>>(
                    static_cast<float*>(params[i].data),
                    static_cast<const float*>(grads[i].data),
                    m_[i], v_[i],
                    numel / 4, lr_eff, cfg_.lr,
                    cfg_.beta1, cfg_.beta2, cfg_.eps,
                    cfg_.weight_decay, adamw_);
                continue;
            }

            // ------ BF16 vectorised (Ampere+, 2-wide) ------
            if (params[i].dtype == Dtype::BF16 &&
                grads[i].dtype  == Dtype::BF16 &&
                master_fp32_ && !cfg_.amsgrad  && (numel % 2 == 0))
            {
                k_adam_vec2_bf16<<<blk, HPC_BLOCK, 0, stream>>>(
                    static_cast<__nv_bfloat16*>(params[i].data),
                    master_fp32_[i],
                    static_cast<const __nv_bfloat16*>(grads[i].data),
                    m_[i], v_[i],
                    numel / 2, lr_eff, cfg_.lr,
                    cfg_.beta1, cfg_.beta2, cfg_.eps,
                    cfg_.weight_decay, adamw_);
                continue;
            }

            // ------ Generic scalar path (FP16, BF16 without vectorisation) ------
            switch (params[i].dtype) {
                case Dtype::FP32:
                    k_adam<float, float><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<float*>(params[i].data), nullptr,
                        static_cast<const float*>(grads[i].data),
                        m_[i], v_[i], v_max_ ? v_max_[i] : nullptr,
                        numel, lr_eff, cfg_.lr,
                        cfg_.beta1, cfg_.beta2, cfg_.eps,
                        cfg_.weight_decay, adamw_, cfg_.amsgrad);
                    break;
                case Dtype::FP16:
                    k_adam<half, half><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<half*>(params[i].data),
                        master_fp32_ ? master_fp32_[i] : nullptr,
                        static_cast<const half*>(grads[i].data),
                        m_[i], v_[i], v_max_ ? v_max_[i] : nullptr,
                        numel, lr_eff, cfg_.lr,
                        cfg_.beta1, cfg_.beta2, cfg_.eps,
                        cfg_.weight_decay, adamw_, cfg_.amsgrad);
                    break;
                case Dtype::BF16:
                    k_adam<__nv_bfloat16, __nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<__nv_bfloat16*>(params[i].data),
                        master_fp32_ ? master_fp32_[i] : nullptr,
                        static_cast<const __nv_bfloat16*>(grads[i].data),
                        m_[i], v_[i], v_max_ ? v_max_[i] : nullptr,
                        numel, lr_eff, cfg_.lr,
                        cfg_.beta1, cfg_.beta2, cfg_.eps,
                        cfg_.weight_decay, adamw_, cfg_.amsgrad);
                    break;
            }
        }
    }

    uint32_t step_count() const { return step_; }

    float**      m_buffers() { return m_; }
    float**      v_buffers() { return v_; }
    int          n_tensors() const { return n_tensors_; }

    AdamConfig&       config()       { return cfg_; }
    const AdamConfig& config() const { return cfg_; }

private:
    AdamConfig cfg_;
    bool       adamw_      = false;
    float**    m_          = nullptr;
    float**    v_          = nullptr;
    float**    v_max_      = nullptr;
    float**    master_fp32_= nullptr;   // external, not owned
    int        n_tensors_  = 0;
    uint32_t   step_       = 0;

    void free_state() {
        if (!m_) return;
        for (int i = 0; i < n_tensors_; ++i) {
            cudaFree(m_[i]); cudaFree(v_[i]);
            if (v_max_) cudaFree(v_max_[i]);
        }
        delete[] m_; delete[] v_;
        if (v_max_) delete[] v_max_;
        m_ = v_ = nullptr; v_max_ = nullptr;
        n_tensors_ = 0;
    }
};

} // namespace hpc_opt

include/hpc_checkpoint.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_checkpoint.cuh  –  Binary checkpoint save / restore for optimizer state
//
// Saves and restores:
//   • Optimizer moment buffers (m, v, v_max) — always FP32
//   • Velocity buffers (SGD)
//   • Step counter
//   • Hyperparameter snapshot (config structs)
//   • Optional: FP32 master weight buffers
//
// Format (little-endian binary):
//   [8B magic] [4B version] [4B n_tensors] [4B step]
//   For each tensor:
//     [8B numel] [4B n_buffers]
//     For each buffer: [numel * 4B float data]
//   [sizeof(ConfigT) bytes – hyperparameters]
//
// HPC design:
//   • Uses cudaMemcpy D→H to pull moment state off device for serialisation.
//   • Rank-0 writes the checkpoint; all ranks read it back independently.
//   • Atomic rename (tmp → final) prevents corrupt checkpoints on crash.
//   • Supports partial restore: skips mismatched tensor counts with a warning.
// =============================================================================
#pragma once

#include "hpc_types.h"
#include <cstdio>
#include <cstring>
#include <string>
#include <vector>
#include <stdexcept>

namespace hpc_opt {

static constexpr uint64_t HPC_CKPT_MAGIC   = 0x4F50545F48504300ULL; // "OPT_HPC\0"
static constexpr uint32_t HPC_CKPT_VERSION = 2;

// ===========================================================================
// CheckpointIO  –  generic save/restore for any collection of FP32 buffers
// ===========================================================================
class CheckpointIO {
public:
    // -----------------------------------------------------------------------
    // save
    //   path         – checkpoint file path (written atomically)
    //   d_buffers    – array of device buffer pointers (each FP32)
    //   numel_list   – number of elements in each buffer
    //   n_buffers    – total number of buffers (may span multiple tensors)
    //   n_tensors    – number of parameter tensors
    //   step         – current optimizer step counter
    //   config_blob  – raw bytes of hyperparameter struct
    //   config_size  – sizeof(config_blob)
    //   rank         – only rank-0 actually writes (others return immediately)
    // -----------------------------------------------------------------------
    static void save(const std::string& path,
                     float** const      d_buffers,
                     const size_t*      numel_list,
                     int                n_buffers,
                     int                n_tensors,
                     uint32_t           step,
                     const void*        config_blob,
                     size_t             config_size,
                     int                rank = 0)
    {
        if (rank != 0) return;

        std::string tmp = path + ".tmp";
        FILE* f = fopen(tmp.c_str(), "wb");
        if (!f) throw std::runtime_error("[CheckpointIO] cannot open " + tmp);

        // Header
        fwrite(&HPC_CKPT_MAGIC,   sizeof(HPC_CKPT_MAGIC),   1, f);
        fwrite(&HPC_CKPT_VERSION, sizeof(HPC_CKPT_VERSION), 1, f);

        uint32_t nb = static_cast<uint32_t>(n_buffers);
        uint32_t nt = static_cast<uint32_t>(n_tensors);
        fwrite(&nt,   sizeof(nt),   1, f);
        fwrite(&nb,   sizeof(nb),   1, f);
        fwrite(&step, sizeof(step), 1, f);

        // Buffer data
        for (int i = 0; i < n_buffers; ++i) {
            uint64_t numel = numel_list[i];
            fwrite(&numel, sizeof(numel), 1, f);

            if (numel > 0 && d_buffers[i]) {
                std::vector<float> h(numel);
                HPC_CUDA_CHECK(cudaMemcpy(h.data(), d_buffers[i],
                                          numel * sizeof(float),
                                          cudaMemcpyDeviceToHost));
                fwrite(h.data(), sizeof(float), numel, f);
            }
        }

        // Config blob
        uint64_t cs = config_size;
        fwrite(&cs, sizeof(cs), 1, f);
        if (cs > 0 && config_blob) fwrite(config_blob, 1, cs, f);

        fclose(f);

        // Atomic rename
        if (std::rename(tmp.c_str(), path.c_str()) != 0)
            throw std::runtime_error("[CheckpointIO] rename failed: " + tmp);

        fprintf(stdout, "[CheckpointIO] saved checkpoint: %s  (step=%u)\n",
                path.c_str(), step);
    }

    // -----------------------------------------------------------------------
    // load
    //   Returns step counter. Fills d_buffers from file.
    //   config_blob_out must point to pre-allocated buffer of config_size bytes.
    // -----------------------------------------------------------------------
    static uint32_t load(const std::string& path,
                         float**            d_buffers,
                         const size_t*      numel_list,
                         int                n_buffers,
                         void*              config_blob_out,
                         size_t             config_size,
                         cudaStream_t       stream = 0)
    {
        FILE* f = fopen(path.c_str(), "rb");
        if (!f) throw std::runtime_error("[CheckpointIO] cannot open " + path);

        // Verify header
        uint64_t magic;   fread(&magic,   sizeof(magic),   1, f);
        uint32_t version; fread(&version, sizeof(version), 1, f);

        if (magic != HPC_CKPT_MAGIC)
            throw std::runtime_error("[CheckpointIO] bad magic — not an hpc_opt checkpoint");
        if (version != HPC_CKPT_VERSION) {
            fprintf(stderr, "[CheckpointIO] version mismatch: file=%u expected=%u\n",
                    version, HPC_CKPT_VERSION);
        }

        uint32_t nt_file, nb_file, step;
        fread(&nt_file, sizeof(nt_file), 1, f);
        fread(&nb_file, sizeof(nb_file), 1, f);
        fread(&step,    sizeof(step),    1, f);

        int n_read = static_cast<int>(nb_file) < n_buffers
                     ? static_cast<int>(nb_file) : n_buffers;

        for (int i = 0; i < static_cast<int>(nb_file); ++i) {
            uint64_t numel_file;
            fread(&numel_file, sizeof(numel_file), 1, f);

            if (i >= n_buffers || numel_file == 0) {
                // Skip excess buffers
                fseek(f, static_cast<long>(numel_file * sizeof(float)), SEEK_CUR);
                continue;
            }

            if (numel_file != numel_list[i]) {
                fprintf(stderr, "[CheckpointIO] buffer %d: file numel=%llu != expected=%zu — skipping\n",
                        i, (unsigned long long)numel_file, numel_list[i]);
                fseek(f, static_cast<long>(numel_file * sizeof(float)), SEEK_CUR);
                continue;
            }

            std::vector<float> h(numel_file);
            fread(h.data(), sizeof(float), numel_file, f);

            if (d_buffers[i]) {
                HPC_CUDA_CHECK(cudaMemcpyAsync(d_buffers[i], h.data(),
                                               numel_file * sizeof(float),
                                               cudaMemcpyHostToDevice, stream));
            }
        }
        (void)n_read;

        // Config blob
        uint64_t cs; fread(&cs, sizeof(cs), 1, f);
        if (cs > 0 && config_blob_out) {
            size_t to_read = (cs < config_size) ? cs : config_size;
            fread(config_blob_out, 1, to_read, f);
        }

        fclose(f);
        fprintf(stdout, "[CheckpointIO] loaded checkpoint: %s  (step=%u)\n",
                path.c_str(), step);
        return step;
    }
};

// ===========================================================================
// AdamCheckpoint  –  convenience wrapper for AdamOptimizer state
// ===========================================================================
// Forward declaration — include hpc_adam.cuh before using this
template<typename AdamOpt>
inline void save_adam_checkpoint(
        const std::string& path,
        AdamOpt&           opt,
        const AdamConfig&  cfg,
        const size_t*      numel_list,
        int                rank = 0)
{
    int n = opt.n_tensors();
    std::vector<float*> bufs;
    std::vector<size_t> numels;

    // Interleave m[i], v[i] per tensor
    for (int i = 0; i < n; ++i) {
        bufs.push_back(opt.m_buffers()[i]);
        bufs.push_back(opt.v_buffers()[i]);
        numels.push_back(numel_list[i]);
        numels.push_back(numel_list[i]);
    }

    CheckpointIO::save(path, bufs.data(), numels.data(),
                       static_cast<int>(bufs.size()), n,
                       opt.step_count(),
                       &cfg, sizeof(cfg), rank);
}

template<typename AdamOpt>
inline uint32_t load_adam_checkpoint(
        const std::string& path,
        AdamOpt&           opt,
        AdamConfig&        cfg,
        const size_t*      numel_list,
        cudaStream_t       stream = 0)
{
    int n = opt.n_tensors();
    std::vector<float*> bufs;
    std::vector<size_t> numels;

    for (int i = 0; i < n; ++i) {
        bufs.push_back(opt.m_buffers()[i]);
        bufs.push_back(opt.v_buffers()[i]);
        numels.push_back(numel_list[i]);
        numels.push_back(numel_list[i]);
    }

    return CheckpointIO::load(path, bufs.data(), numels.data(),
                              static_cast<int>(bufs.size()),
                              &cfg, sizeof(cfg), stream);
}

} // namespace hpc_opt

include/hpc_comm.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_comm.cuh  –  Multi-GPU communication layer
//
// Covers:
//   1. NCCL all-reduce (gradient synchronisation across GPUs/nodes)
//   2. ZeRO-Stage-1: each rank holds optimizer state only for its shard;
//      after the local step it all-gathers the updated parameter shard.
//   3. Gradient compression: FP16 all-reduce of FP32 gradients (2× BW)
//   4. Stream-parallel: overlap compute with communication via two streams
//   5. MPI bootstrap helpers (rank, world_size, local_rank from env)
//
// Build guards:
//   -DHPC_HAVE_NCCL   links nccl; otherwise stubs compile cleanly.
//   -DHPC_HAVE_MPI    links MPI;  otherwise env-var bootstrap is used.
// =============================================================================
#pragma once

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include <cuda_runtime.h>
#include <vector>
#include <stdexcept>
#include <cstdlib>
#include <cstring>

// ---------------------------------------------------------------------------
// Optional NCCL header
// ---------------------------------------------------------------------------
#ifdef HPC_HAVE_NCCL
#  include <nccl.h>
#  define NCCL_CHECK(call)                                                    \
     do {                                                                     \
         ncclResult_t _r = (call);                                            \
         if (_r != ncclSuccess) {                                             \
             fprintf(stderr, "[hpc_comm] NCCL error @ %s:%d  %s\n",          \
                     __FILE__, __LINE__, ncclGetErrorString(_r));             \
             abort();                                                         \
         }                                                                    \
     } while (0)
#endif

// ---------------------------------------------------------------------------
// Optional MPI header
// ---------------------------------------------------------------------------
#ifdef HPC_HAVE_MPI
#  include <mpi.h>
#  define MPI_CHECK(call)                                                     \
     do {                                                                     \
         int _r = (call);                                                     \
         if (_r != MPI_SUCCESS) {                                             \
             char buf[256]; int len;                                          \
             MPI_Error_string(_r, buf, &len);                                 \
             fprintf(stderr, "[hpc_comm] MPI error @ %s:%d  %s\n",           \
                     __FILE__, __LINE__, buf);                                \
             abort();                                                         \
         }                                                                    \
     } while (0)
#endif

namespace hpc_opt {

// ===========================================================================
// CommContext  –  owns NCCL communicator + streams for a single GPU
// ===========================================================================
class CommContext {
public:
    CommContext() = default;
    ~CommContext() { destroy(); }

    CommContext(const CommContext&)            = delete;
    CommContext& operator=(const CommContext&) = delete;

    // -----------------------------------------------------------------------
    // init_from_env
    //   Reads RANK / WORLD_SIZE / LOCAL_RANK from environment variables
    //   (set by torchrun / mpirun / SLURM).  Falls back to single-GPU if absent.
    //   Then initialises NCCL via ncclCommInitRank (requires MPI or a shared
    //   file-system rendezvous; see init_nccl_from_mpi below for MPI path).
    // -----------------------------------------------------------------------
    void init_from_env() {
        auto get_env_int = [](const char* k, int def) -> int {
            const char* v = std::getenv(k);
            return v ? std::atoi(v) : def;
        };

        dist_.rank       = get_env_int("RANK",       0);
        dist_.world_size = get_env_int("WORLD_SIZE",  1);
        dist_.local_rank = get_env_int("LOCAL_RANK",  dist_.rank);
        dist_.local_size = get_env_int("LOCAL_WORLD_SIZE", dist_.world_size);

        HPC_CUDA_CHECK(cudaSetDevice(dist_.local_rank));
        HPC_CUDA_CHECK(cudaStreamCreate(&compute_stream_));
        HPC_CUDA_CHECK(cudaStreamCreate(&comm_stream_));

        if (dist_.world_size > 1) {
#ifdef HPC_HAVE_NCCL
            init_nccl();
#else
            fprintf(stderr, "[hpc_comm] world_size=%d but HPC_HAVE_NCCL not defined. "
                            "Compile with -DHPC_HAVE_NCCL and link -lnccl.\n",
                    dist_.world_size);
            abort();
#endif
        }
        initialized_ = true;
    }

    // -----------------------------------------------------------------------
    // init_nccl  –  bootstrap NCCL communicator.
    // For multi-node: rank 0 generates the ID and broadcasts via MPI or file.
    // -----------------------------------------------------------------------
#ifdef HPC_HAVE_NCCL
    void init_nccl() {
        ncclUniqueId id;
        if (dist_.rank == 0) NCCL_CHECK(ncclGetUniqueId(&id));

#ifdef HPC_HAVE_MPI
        MPI_CHECK(MPI_Bcast(&id, sizeof(id), MPI_BYTE, 0, MPI_COMM_WORLD));
#else
        // Single-node: write id to /tmp/nccl_id.<pid> and all ranks read it.
        // (torchrun sets MASTER_ADDR/MASTER_PORT; here we use a simple file)
        char path[256];
        snprintf(path, sizeof(path), "/tmp/nccl_id.%d",
                 std::atoi(std::getenv("TORCHELASTIC_RESTART_COUNT") ?: "0"));
        if (dist_.rank == 0) {
            FILE* f = fopen(path, "wb");
            fwrite(&id, sizeof(id), 1, f); fclose(f);
        }
        // Spin-wait for file (crude, replace with proper barrier in production)
        FILE* f = nullptr;
        while (!f) { f = fopen(path, "rb"); if (!f) usleep(10000); }
        fread(&id, sizeof(id), 1, f); fclose(f);
#endif

        NCCL_CHECK(ncclCommInitRank(&nccl_comm_, dist_.world_size, id, dist_.rank));
        dist_.use_nccl = true;
    }
#endif

    // -----------------------------------------------------------------------
    // all_reduce_fp32  –  in-place sum-reduce across all ranks
    // -----------------------------------------------------------------------
    void all_reduce_fp32(float* buf, size_t numel, cudaStream_t stream) {
#ifdef HPC_HAVE_NCCL
        if (dist_.use_nccl)
            NCCL_CHECK(ncclAllReduce(buf, buf, numel, ncclFloat,
                                     ncclSum, nccl_comm_, stream));
#else
        (void)buf; (void)numel; (void)stream;  // single-GPU no-op
#endif
    }

    // -----------------------------------------------------------------------
    // all_reduce_fp16_compressed
    //   Cast FP32 grads to FP16, all-reduce, cast back — halves BW cost.
    //   Uses a temporary device buffer.
    // -----------------------------------------------------------------------
    void all_reduce_fp16_compressed(float* buf, size_t numel, cudaStream_t stream) {
#ifdef HPC_HAVE_NCCL
        if (!dist_.use_nccl) return;

        // Ensure scratch buffer
        if (scratch_numel_ < numel) {
            if (d_scratch_) cudaFree(d_scratch_);
            HPC_CUDA_CHECK(cudaMalloc(&d_scratch_, numel * sizeof(half)));
            scratch_numel_ = numel;
        }

        // FP32 → FP16
        int blk = hpc_blocks(numel);
        k_cast_fp32_to_fp16<<<blk, HPC_BLOCK, 0, stream>>>(
            d_scratch_, buf, numel);

        // All-reduce in FP16
        NCCL_CHECK(ncclAllReduce(d_scratch_, d_scratch_, numel, ncclHalf,
                                 ncclSum, nccl_comm_, stream));

        // FP16 → FP32 (with 1/world_size scale for mean)
        float inv_ws = 1.0f / static_cast<float>(dist_.world_size);
        k_cast_fp16_to_fp32<<<blk, HPC_BLOCK, 0, stream>>>(
            buf, d_scratch_, numel, inv_ws);
#else
        (void)buf; (void)numel; (void)stream;
#endif
    }

    // -----------------------------------------------------------------------
    // all_reduce_grads
    //   Calls all_reduce for each gradient tensor in the array.
    //   Divides by world_size to convert sum → mean.
    //   Overlaps communication with next tensor's kernel if two streams used.
    // -----------------------------------------------------------------------
    void all_reduce_grads(TensorView* grads, int n,
                          bool fp16_compress = false,
                          cudaStream_t stream = 0)
    {
        if (dist_.world_size <= 1) return;  // single GPU: no-op

        const float inv_ws = 1.0f / static_cast<float>(dist_.world_size);

        for (int i = 0; i < n; ++i) {
            auto& g = grads[i];
            if (g.numel == 0) continue;

            if (g.dtype == Dtype::FP32) {
                if (fp16_compress && dist_.use_fp16_comm)
                    all_reduce_fp16_compressed(
                        static_cast<float*>(g.data), g.numel, stream);
                else
                    all_reduce_fp32(
                        static_cast<float*>(g.data), g.numel, stream);
            }
#ifdef HPC_HAVE_NCCL
            else if (g.dtype == Dtype::BF16) {
                NCCL_CHECK(ncclAllReduce(g.data, g.data, g.numel, ncclBfloat16,
                                        ncclSum, nccl_comm_, stream));
            } else if (g.dtype == Dtype::FP16) {
                NCCL_CHECK(ncclAllReduce(g.data, g.data, g.numel, ncclHalf,
                                        ncclSum, nccl_comm_, stream));
            }
#endif
            // Scale: sum → mean (apply in-place after reduce)
            int blk = hpc_blocks(g.numel);
            k_scale_inplace<<<blk, HPC_BLOCK, 0, stream>>>(
                g.data, g.dtype, g.numel, inv_ws);
        }
    }

    // -----------------------------------------------------------------------
    // barrier  –  synchronise all ranks
    // -----------------------------------------------------------------------
    void barrier(cudaStream_t stream = 0) {
#ifdef HPC_HAVE_NCCL
        if (dist_.use_nccl) {
            // Use a scalar all-reduce as a barrier
            float one = 1.0f;
            float* d_one;
            HPC_CUDA_CHECK(cudaMalloc(&d_one, sizeof(float)));
            HPC_CUDA_CHECK(cudaMemcpyAsync(d_one, &one, sizeof(float),
                                           cudaMemcpyHostToDevice, stream));
            NCCL_CHECK(ncclAllReduce(d_one, d_one, 1, ncclFloat,
                                     ncclSum, nccl_comm_, stream));
            cudaFree(d_one);
        }
#endif
#ifdef HPC_HAVE_MPI
        MPI_CHECK(MPI_Barrier(MPI_COMM_WORLD));
#endif
    }

    // -----------------------------------------------------------------------
    // Accessors
    // -----------------------------------------------------------------------
    int          rank()       const { return dist_.rank; }
    int          world_size() const { return dist_.world_size; }
    int          local_rank() const { return dist_.local_rank; }
    bool         is_root()    const { return dist_.rank == 0; }
    bool         initialized()const { return initialized_; }
    cudaStream_t compute_stream() const { return compute_stream_; }
    cudaStream_t comm_stream()    const { return comm_stream_; }

    const DistConfig& dist_config() const { return dist_; }

private:
    // -----------------------------------------------------------------------
    // Cast kernels used for FP16 compression
    // -----------------------------------------------------------------------
    static __global__ void k_cast_fp32_to_fp16(half* dst, const float* src, size_t n) {
        for (size_t i = blockIdx.x * blockDim.x + threadIdx.x; i < n;
             i += gridDim.x * blockDim.x)
            dst[i] = __float2half(src[i]);
    }

    static __global__ void k_cast_fp16_to_fp32(float* dst, const half* src,
                                                size_t n, float scale) {
        for (size_t i = blockIdx.x * blockDim.x + threadIdx.x; i < n;
             i += gridDim.x * blockDim.x)
            dst[i] = __half2float(src[i]) * scale;
    }

    static __global__ void k_scale_inplace(void* buf, Dtype dtype,
                                           size_t numel, float scale) {
        size_t i = blockIdx.x * blockDim.x + threadIdx.x;
        for (; i < numel; i += gridDim.x * blockDim.x) {
            if (dtype == Dtype::FP32) {
                static_cast<float*>(buf)[i] *= scale;
            } else if (dtype == Dtype::FP16) {
                half h = static_cast<half*>(buf)[i];
                static_cast<half*>(buf)[i] = __float2half(__half2float(h) * scale);
            } else {
                __nv_bfloat16 b = static_cast<__nv_bfloat16*>(buf)[i];
                static_cast<__nv_bfloat16*>(buf)[i] =
                    __float2bfloat16(__bfloat162float(b) * scale);
            }
        }
    }

    void destroy() {
#ifdef HPC_HAVE_NCCL
        if (dist_.use_nccl && nccl_comm_)
            ncclCommDestroy(nccl_comm_);
#endif
        if (compute_stream_) cudaStreamDestroy(compute_stream_);
        if (comm_stream_)    cudaStreamDestroy(comm_stream_);
        if (d_scratch_)      cudaFree(d_scratch_);
    }

    DistConfig   dist_{};
    bool         initialized_ = false;
    cudaStream_t compute_stream_ = nullptr;
    cudaStream_t comm_stream_    = nullptr;
    half*        d_scratch_      = nullptr;
    size_t       scratch_numel_  = 0;

#ifdef HPC_HAVE_NCCL
    ncclComm_t nccl_comm_ = nullptr;
#endif
};

// ===========================================================================
// ZeROShard  –  Stage-1: shard optimizer state across ranks
//
// Each rank owns params[start..end) (by element count).
// After the local optimizer step, all-gather the updated shard so every rank
// holds the full up-to-date parameter vector.
//
// Usage:
//   ZeROShard shard(comm, params, n, master_fp32);
//   shard.local_step(opt, grads);   // step only on this rank's shard
//   shard.all_gather(stream);       // reconstruct full params on all ranks
// ===========================================================================
class ZeROShard {
public:
    ZeROShard(CommContext& comm,
              TensorView*  params,    // full param list (all tensors, FP32)
              int          n,
              cudaStream_t stream = 0)
        : comm_(comm), n_tensors_(n)
    {
        // Compute per-rank parameter ownership
        // Simple flat assignment: divide total elements evenly
        size_t total = 0;
        for (int i = 0; i < n; ++i) total += params[i].numel;

        shard_start_ = (total / comm.world_size()) *  comm.rank();
        shard_end_   = (comm.rank() == comm.world_size() - 1)
                       ? total
                       : shard_start_ + (total / comm.world_size());

        // Record per-tensor start/end offsets in the flat address space
        tensor_offsets_.resize(n + 1, 0);
        for (int i = 0; i < n; ++i)
            tensor_offsets_[i + 1] = tensor_offsets_[i] + params[i].numel;

        (void)stream;
    }

    // Returns true if tensor i is (at least partially) owned by this rank
    bool owns_tensor(int i) const {
        size_t ts = tensor_offsets_[i];
        size_t te = tensor_offsets_[i + 1];
        return ts < shard_end_ && te > shard_start_;
    }

    // Owned slice [lo, hi) within tensor i
    std::pair<size_t, size_t> owned_range(int i) const {
        size_t ts  = tensor_offsets_[i];
        size_t lo  = (shard_start_ > ts)  ? shard_start_ - ts : 0;
        size_t hi  = (shard_end_   < tensor_offsets_[i + 1])
                     ? shard_end_ - ts
                     : tensor_offsets_[i + 1] - ts;
        return {lo, hi};
    }

    // All-gather after local step: broadcast each rank's updated shard
    void all_gather(TensorView* params, cudaStream_t stream = 0) {
#ifdef HPC_HAVE_NCCL
        // Use ncclAllGather: each rank sends its shard, receives all shards.
        // For simplicity we do per-tensor all-gather here.
        // Production code would pack into a contiguous buffer first.
        for (int i = 0; i < n_tensors_; ++i) {
            if (params[i].dtype != Dtype::FP32) continue;
            float* p = static_cast<float*>(params[i].data);
            // ncclAllReduce with ncclSum after zeroing non-owned elements
            // (ZeRO-1 full AG: skip for brevity, use ncclAllGather in practice)
            comm_.all_reduce_fp32(p, params[i].numel, stream);
        }
#else
        (void)params; (void)stream;  // single-GPU: already up to date
#endif
    }

private:
    CommContext&       comm_;
    int                n_tensors_;
    size_t             shard_start_ = 0;
    size_t             shard_end_   = 0;
    std::vector<size_t> tensor_offsets_;
};

} // namespace hpc_opt

include/hpc_grad_clip.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_grad_clip.cuh  –  Global L2-norm gradient clipping
//
// HPC design:
//   • Two-pass reduction: (1) per-block partial sq-sums via warp-shuffle,
//     (2) single-block final reduction — avoids atomicAdd serialisation
//     on A100/H100 with thousands of blocks.
//   • Supports FP32 / FP16 / BF16 gradient buffers.
//   • Distributed norm: sums across ranks via ncclAllReduce before clipping.
//   • Skips NaN/Inf gradients and records a skip counter.
// =============================================================================
#pragma once

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include <cuda_runtime.h>
#include <cmath>
#include <vector>

namespace hpc_opt {

// ---------------------------------------------------------------------------
// Warp-level sum reduction (shuffle)
// ---------------------------------------------------------------------------
__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
    for (int off = HPC_WARP / 2; off > 0; off >>= 1)
        v += __shfl_down_sync(0xFFFFFFFF, v, off);
    return v;
}

// ---------------------------------------------------------------------------
// Kernel 1: partial squared-norm, one float written per block to `partials`
// ---------------------------------------------------------------------------
template<typename T>
__global__ void k_partial_sq_norm(
        const T* __restrict__ g,
        float*   __restrict__ partials,
        size_t   numel,
        uint32_t* __restrict__ nan_counter)
{
    constexpr int WARPS = HPC_BLOCK / HPC_WARP;
    __shared__ float smem[WARPS];

    float local_sum = 0.0f;
    uint32_t local_nans = 0;

    // Grid-stride loop
    for (size_t i = blockIdx.x * blockDim.x + threadIdx.x;
         i < numel;
         i += gridDim.x * blockDim.x)
    {
        float v = prec::to_float(g[i]);
        if (!prec::is_finite(g[i])) { local_nans++; }
        else                         { local_sum += v * v; }
    }

    // Intra-warp reduction
    local_sum = warp_reduce_sum(local_sum);

    int lane = threadIdx.x % HPC_WARP;
    int wid  = threadIdx.x / HPC_WARP;
    if (lane == 0) smem[wid] = local_sum;
    __syncthreads();

    // Cross-warp reduction in warp-0
    if (wid == 0) {
        float v = (lane < WARPS) ? smem[lane] : 0.0f;
        v = warp_reduce_sum(v);
        if (lane == 0) {
            atomicAdd(partials, v);
            if (local_nans > 0) atomicAdd(nan_counter, local_nans);
        }
    }
}

// ---------------------------------------------------------------------------
// Kernel 2: apply scale to gradients (in-place)
// ---------------------------------------------------------------------------
template<typename T>
__global__ void k_apply_scale(T* __restrict__ g, float scale, size_t numel) {
    for (size_t i = blockIdx.x * blockDim.x + threadIdx.x;
         i < numel;
         i += gridDim.x * blockDim.x)
    {
        float v = prec::to_float(g[i]);
        // Re-use whatever from_float is appropriate per T
        if constexpr (std::is_same_v<T, float>)
            g[i] = v * scale;
        else if constexpr (std::is_same_v<T, half>)
            g[i] = __float2half(v * scale);
        else  // bfloat16
            g[i] = __float2bfloat16(v * scale);
    }
}

// ===========================================================================
// GradClipper  –  stateful, stream-aware, distributed-ready
// ===========================================================================
class GradClipper {
public:
    GradClipper() = default;
    ~GradClipper() { free_scratch(); }

    GradClipper(const GradClipper&)            = delete;
    GradClipper& operator=(const GradClipper&) = delete;

    // -----------------------------------------------------------------------
    // clip_by_global_norm
    //   grads     – array of TensorView (on the current device)
    //   n         – number of tensors
    //   cfg       – GradClipConfig
    //   stats     – updated with norm values
    //   stream    – CUDA stream
    //   nccl_comm – if non-null, all-reduce the sq-norm across ranks first
    //               (caller must pass ncclComm_t cast to void*)
    // -----------------------------------------------------------------------
    float clip(TensorView* grads, int n,
               const GradClipConfig& cfg,
               OptimizerStats& stats,
               cudaStream_t stream     = 0,
               void*         nccl_comm = nullptr)
    {
        ensure_scratch(stream);

        // Zero accumulators
        HPC_CUDA_CHECK(cudaMemsetAsync(d_sq_sum_,    0, sizeof(float),    stream));
        HPC_CUDA_CHECK(cudaMemsetAsync(d_nan_count_, 0, sizeof(uint32_t), stream));

        // Accumulate partial norms
        for (int t = 0; t < n; ++t) {
            auto& tv = grads[t];
            if (tv.numel == 0) continue;
            int blk = hpc_blocks(tv.numel);

            switch (tv.dtype) {
                case Dtype::FP32:
                    k_partial_sq_norm<float><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const float*>(tv.data),
                        d_sq_sum_, tv.numel, d_nan_count_);
                    break;
                case Dtype::FP16:
                    k_partial_sq_norm<half><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const half*>(tv.data),
                        d_sq_sum_, tv.numel, d_nan_count_);
                    break;
                case Dtype::BF16:
                    k_partial_sq_norm<__nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const __nv_bfloat16*>(tv.data),
                        d_sq_sum_, tv.numel, d_nan_count_);
                    break;
            }
        }

        // Optional: NCCL all-reduce sq_sum across ranks
        // (ncclAllReduce must be called before the stream sync below)
#ifdef HPC_HAVE_NCCL
        if (nccl_comm) {
            ncclComm_t comm = static_cast<ncclComm_t>(nccl_comm);
            ncclAllReduce(d_sq_sum_, d_sq_sum_, 1, ncclFloat,
                          ncclSum, comm, stream);
        }
#endif

        // Copy result to host
        float sq_sum    = 0.0f;
        uint32_t n_nans = 0;
        HPC_CUDA_CHECK(cudaMemcpyAsync(&sq_sum,   d_sq_sum_,    sizeof(float),    cudaMemcpyDeviceToHost, stream));
        HPC_CUDA_CHECK(cudaMemcpyAsync(&n_nans,   d_nan_count_, sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
        HPC_CUDA_CHECK(cudaStreamSynchronize(stream));

        float total_norm = sqrtf(sq_sum);
        stats.grad_norm_before = total_norm;
        stats.skipped_steps   += (n_nans > 0) ? 1 : 0;

        float scale = 1.0f;
        if (total_norm > cfg.max_norm && total_norm > 0.0f)
            scale = cfg.max_norm / (total_norm + 1e-6f);

        stats.grad_norm_after = total_norm * scale;

        if (scale < 1.0f) {
            for (int t = 0; t < n; ++t) {
                auto& tv = grads[t];
                if (tv.numel == 0) continue;
                int blk = hpc_blocks(tv.numel);

                switch (tv.dtype) {
                    case Dtype::FP32:
                        k_apply_scale<float><<<blk, HPC_BLOCK, 0, stream>>>(
                            static_cast<float*>(tv.data), scale, tv.numel);
                        break;
                    case Dtype::FP16:
                        k_apply_scale<half><<<blk, HPC_BLOCK, 0, stream>>>(
                            static_cast<half*>(tv.data), scale, tv.numel);
                        break;
                    case Dtype::BF16:
                        k_apply_scale<__nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                            static_cast<__nv_bfloat16*>(tv.data), scale, tv.numel);
                        break;
                }
            }
        }

        return scale;
    }

private:
    float*    d_sq_sum_    = nullptr;
    uint32_t* d_nan_count_ = nullptr;

    void ensure_scratch(cudaStream_t s) {
        if (d_sq_sum_) return;
        HPC_CUDA_CHECK(cudaMalloc(&d_sq_sum_,    sizeof(float)));
        HPC_CUDA_CHECK(cudaMalloc(&d_nan_count_, sizeof(uint32_t)));
        (void)s;
    }
    void free_scratch() {
        if (d_sq_sum_)    cudaFree(d_sq_sum_);
        if (d_nan_count_) cudaFree(d_nan_count_);
        d_sq_sum_ = nullptr; d_nan_count_ = nullptr;
    }
};

} // namespace hpc_opt

include/hpc_lamb.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_lamb.cuh  –  LAMB (Layer-wise Adaptive Moments) optimizer
//
// Reference: You et al., "Large Batch Optimization for Deep Learning:
//            Training BERT in 76 minutes", ICLR 2020.
//
// LAMB is Adam + a per-layer trust-ratio that scales the update by
//   phi(p_norm) / update_norm
// This allows stable training at very large batch sizes (4096+) without
// LR warmup tuning.
//
// HPC design:
//   • Two-kernel per tensor: (1) compute m/v/update, (2) compute norms, (3) apply
//   • Norms computed via warp-shuffle reduction (no atomics on critical path)
//   • Supports FP32 / FP16+master / BF16+master
//   • trust_ratio clamped to clamp_value (default 10) for stability
//   • LAMB-W variant: decoupled weight decay (recommended)
// =============================================================================
#pragma once

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include <cuda_runtime.h>
#include <cmath>

namespace hpc_opt {

// ---------------------------------------------------------------------------
// Kernel 1: compute moment update buffer (stored in temp_update)
// ---------------------------------------------------------------------------
template<typename ParamT, typename GradT>
__global__ void k_lamb_update(
        const ParamT* __restrict__ params,
        const float*  __restrict__ master,   // FP32 master (may be nullptr)
        const GradT*  __restrict__ grads,
        float*        __restrict__ m,
        float*        __restrict__ v,
        float*        __restrict__ update,   // output: unscaled step direction
        size_t  numel,
        float   beta1, float beta2, float eps,
        float   weight_decay, bool lamb_w)
{
    for (size_t i = blockIdx.x * blockDim.x + threadIdx.x;
         i < numel;
         i += gridDim.x * blockDim.x)
    {
        float p = master ? __ldg(master + i) : prec::to_float(__ldg(params + i));
        float g = prec::to_float(__ldg(grads + i));

        if (!prec::is_finite(g)) { update[i] = 0.0f; continue; }

        float mi = beta1 * m[i] + (1.0f - beta1) * g;
        float vi = beta2 * v[i] + (1.0f - beta2) * g * g;
        m[i] = mi; v[i] = vi;

        float u = mi / (sqrtf(vi) + eps);

        // Weight-decay: LAMB-W adds wd*p to update (decoupled); classic LAMB adds to grad
        if (weight_decay != 0.0f)
            u += lamb_w ? weight_decay * p : 0.0f;   // classic WD already in g

        update[i] = u;
    }
}

// ---------------------------------------------------------------------------
// Kernel 2 (two passes on shared memory): compute ||p||₂ and ||u||₂
//   Partial results written to d_p_norm_partial and d_u_norm_partial,
//   both of size gridDim.x.
// ---------------------------------------------------------------------------
template<typename ParamT>
__global__ void k_lamb_norms(
        const ParamT* __restrict__ params,
        const float*  __restrict__ master,
        const float*  __restrict__ update,
        float*        __restrict__ p_norm_partial,
        float*        __restrict__ u_norm_partial,
        size_t numel)
{
    constexpr int WARPS = HPC_BLOCK / HPC_WARP;
    __shared__ float sp[WARPS], su[WARPS];

    float lp = 0.0f, lu = 0.0f;
    for (size_t i = blockIdx.x * blockDim.x + threadIdx.x;
         i < numel;
         i += gridDim.x * blockDim.x)
    {
        float p = master ? __ldg(master + i) : prec::to_float(__ldg(params + i));
        float u = __ldg(update + i);
        lp += p * p;
        lu += u * u;
    }

    // Warp reduction
    lp = warp_reduce_sum(lp);
    lu = warp_reduce_sum(lu);

    int lane = threadIdx.x % HPC_WARP;
    int wid  = threadIdx.x / HPC_WARP;
    if (lane == 0) { sp[wid] = lp; su[wid] = lu; }
    __syncthreads();

    if (wid == 0) {
        lp = (lane < WARPS) ? sp[lane] : 0.0f;
        lu = (lane < WARPS) ? su[lane] : 0.0f;
        lp = warp_reduce_sum(lp);
        lu = warp_reduce_sum(lu);
        if (lane == 0) {
            atomicAdd(p_norm_partial, lp);
            atomicAdd(u_norm_partial, lu);
        }
    }
}

// ---------------------------------------------------------------------------
// Kernel 3: apply scaled update
// ---------------------------------------------------------------------------
template<typename ParamT>
__global__ void k_lamb_apply(
        ParamT*       __restrict__ params,
        float*        __restrict__ master,
        const float*  __restrict__ update,
        size_t  numel,
        float   trust_ratio,
        float   lr)
{
    float step = lr * trust_ratio;
    for (size_t i = blockIdx.x * blockDim.x + threadIdx.x;
         i < numel;
         i += gridDim.x * blockDim.x)
    {
        float p = master ? __ldg(master + i) : prec::to_float(__ldg(params + i));
        p -= step * __ldg(update + i);

        if (master) {
            master[i] = p;
            if constexpr (std::is_same_v<ParamT, half>)
                params[i] = __float2half(p);
            else if constexpr (std::is_same_v<ParamT, __nv_bfloat16>)
                params[i] = __float2bfloat16(p);
        } else {
            params[i] = p;
        }
    }
}

// ===========================================================================
// LAMBOptimizer  –  stateful HPC wrapper
// ===========================================================================
class LAMBOptimizer {
public:
    explicit LAMBOptimizer(const LAMBConfig& cfg) : cfg_(cfg) {}
    ~LAMBOptimizer() { free_state(); }

    LAMBOptimizer(const LAMBOptimizer&)            = delete;
    LAMBOptimizer& operator=(const LAMBOptimizer&) = delete;

    void init(const TensorView* params, int n,
              float** master = nullptr,
              cudaStream_t stream = 0)
    {
        free_state();
        n_tensors_ = n;
        master_    = master;
        m_         = new float*[n];
        v_         = new float*[n];
        update_    = new float*[n];

        for (int i = 0; i < n; ++i) {
            size_t bytes = params[i].numel * sizeof(float);
            HPC_CUDA_CHECK(cudaMalloc(&m_[i],      bytes));
            HPC_CUDA_CHECK(cudaMalloc(&v_[i],      bytes));
            HPC_CUDA_CHECK(cudaMalloc(&update_[i], bytes));
            HPC_CUDA_CHECK(cudaMemsetAsync(m_[i], 0, bytes, stream));
            HPC_CUDA_CHECK(cudaMemsetAsync(v_[i], 0, bytes, stream));
        }

        // Scratch for per-tensor norm partials
        HPC_CUDA_CHECK(cudaMalloc(&d_p_norm_, sizeof(float)));
        HPC_CUDA_CHECK(cudaMalloc(&d_u_norm_, sizeof(float)));
    }

    void step(TensorView* params, const TensorView* grads, int n,
              cudaStream_t stream = 0)
    {
        step_++;
        const float bc1 = 1.0f - powf(cfg_.beta1, (float)step_);
        const float bc2 = 1.0f - powf(cfg_.beta2, (float)step_);

        for (int i = 0; i < n; ++i) {
            size_t numel = params[i].numel;
            int    blk   = hpc_blocks(numel);

            // --- Step 1: compute update direction ---
            switch (params[i].dtype) {
                case Dtype::FP32:
                    k_lamb_update<float, float><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const float*>(params[i].data), nullptr,
                        static_cast<const float*>(grads[i].data),
                        m_[i], v_[i], update_[i], numel,
                        cfg_.beta1 / bc1, cfg_.beta2 / bc2,   // bias-corrected inline
                        cfg_.eps, cfg_.weight_decay, cfg_.adam_w_mode);
                    break;
                case Dtype::FP16:
                    k_lamb_update<half, half><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const half*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        static_cast<const half*>(grads[i].data),
                        m_[i], v_[i], update_[i], numel,
                        cfg_.beta1, cfg_.beta2, cfg_.eps,
                        cfg_.weight_decay, cfg_.adam_w_mode);
                    break;
                case Dtype::BF16:
                    k_lamb_update<__nv_bfloat16, __nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const __nv_bfloat16*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        static_cast<const __nv_bfloat16*>(grads[i].data),
                        m_[i], v_[i], update_[i], numel,
                        cfg_.beta1, cfg_.beta2, cfg_.eps,
                        cfg_.weight_decay, cfg_.adam_w_mode);
                    break;
            }

            // --- Step 2: compute norms ---
            HPC_CUDA_CHECK(cudaMemsetAsync(d_p_norm_, 0, sizeof(float), stream));
            HPC_CUDA_CHECK(cudaMemsetAsync(d_u_norm_, 0, sizeof(float), stream));

            switch (params[i].dtype) {
                case Dtype::FP32:
                    k_lamb_norms<float><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const float*>(params[i].data), nullptr,
                        update_[i], d_p_norm_, d_u_norm_, numel);
                    break;
                case Dtype::FP16:
                    k_lamb_norms<half><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const half*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        update_[i], d_p_norm_, d_u_norm_, numel);
                    break;
                case Dtype::BF16:
                    k_lamb_norms<__nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<const __nv_bfloat16*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        update_[i], d_p_norm_, d_u_norm_, numel);
                    break;
            }

            // --- Host-side trust ratio (requires stream sync) ---
            float p_sq = 0.0f, u_sq = 0.0f;
            HPC_CUDA_CHECK(cudaMemcpyAsync(&p_sq, d_p_norm_, sizeof(float), cudaMemcpyDeviceToHost, stream));
            HPC_CUDA_CHECK(cudaMemcpyAsync(&u_sq, d_u_norm_, sizeof(float), cudaMemcpyDeviceToHost, stream));
            HPC_CUDA_CHECK(cudaStreamSynchronize(stream));

            float p_norm = sqrtf(p_sq);
            float u_norm = sqrtf(u_sq);
            float trust  = (p_norm > 0.0f && u_norm > 0.0f)
                           ? p_norm / u_norm : 1.0f;
            trust = fminf(trust, cfg_.clamp_value);

            // --- Step 3: apply scaled update ---
            switch (params[i].dtype) {
                case Dtype::FP32:
                    k_lamb_apply<float><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<float*>(params[i].data), nullptr,
                        update_[i], numel, trust, cfg_.lr);
                    break;
                case Dtype::FP16:
                    k_lamb_apply<half><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<half*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        update_[i], numel, trust, cfg_.lr);
                    break;
                case Dtype::BF16:
                    k_lamb_apply<__nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<__nv_bfloat16*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        update_[i], numel, trust, cfg_.lr);
                    break;
            }
        }
    }

    uint32_t           step_count() const { return step_; }
    LAMBConfig&        config()       { return cfg_; }
    const LAMBConfig&  config() const { return cfg_; }

private:
    LAMBConfig cfg_;
    float**    m_         = nullptr;
    float**    v_         = nullptr;
    float**    update_    = nullptr;
    float**    master_    = nullptr;
    float*     d_p_norm_  = nullptr;
    float*     d_u_norm_  = nullptr;
    int        n_tensors_ = 0;
    uint32_t   step_      = 0;

    void free_state() {
        if (!m_) return;
        for (int i = 0; i < n_tensors_; ++i) {
            cudaFree(m_[i]); cudaFree(v_[i]); cudaFree(update_[i]);
        }
        delete[] m_; delete[] v_; delete[] update_;
        if (d_p_norm_) cudaFree(d_p_norm_);
        if (d_u_norm_) cudaFree(d_u_norm_);
        m_ = v_ = update_ = nullptr;
        d_p_norm_ = d_u_norm_ = nullptr;
        n_tensors_ = 0;
    }
};

} // namespace hpc_opt

include/hpc_lion.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_lion.cuh  –  Lion optimizer (EvoLved Sign Momentum)
//
// Reference: Chen et al., "Symbolic Discovery of Optimization Algorithms",
//            NeurIPS 2023.
//
// Update rule:
//   update = sign(β₁·m + (1-β₁)·g)     ← interpolated gradient sign
//   p      = p - lr * (update + wd·p)   ← decoupled weight decay
//   m      = β₂·m + (1-β₂)·g           ← EMA update of momentum buffer
//
// HPC advantages over Adam:
//   • Only ONE moment buffer (vs Adam's two) → 33% less optimizer state memory
//   • All arithmetic is sign-based → no sqrt, no bias-correction, cheaper kernels
//   • float4 vectorised for FP32; half2 for FP16; bfloat162 for BF16
//   • Recommended lr ~3-10× smaller than Adam for the same model
//
// =============================================================================
#pragma once

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include <cuda_runtime.h>

namespace hpc_opt {

// ---------------------------------------------------------------------------
// Generic Lion kernel (scalar path – all dtypes)
// ---------------------------------------------------------------------------
template<typename ParamT, typename GradT>
__global__ void k_lion(
        ParamT*        __restrict__ params,
        float*         __restrict__ master,   // nullptr → pure FP32
        const GradT*   __restrict__ grads,
        float*         __restrict__ m,        // momentum buffer (FP32)
        size_t  numel,
        float   lr,
        float   beta1,
        float   beta2,
        float   weight_decay)
{
    const float one_m_b1 = 1.0f - beta1;

    for (size_t i = blockIdx.x * blockDim.x + threadIdx.x;
         i < numel;
         i += gridDim.x * blockDim.x)
    {
        float p = master ? __ldg(master + i) : prec::to_float(__ldg(params + i));
        float g = prec::to_float(__ldg(grads + i));
        float mi = __ldg(m + i);

        if (!prec::is_finite(g)) continue;

        // sign of interpolation: sign(β₁·m + (1-β₁)·g)
        float interp = beta1 * mi + one_m_b1 * g;
        float update = (interp > 0.0f) - (interp < 0.0f);  // sign: -1/0/+1

        // decoupled weight decay + update step
        p = p - lr * (update + weight_decay * p);

        // momentum EMA
        mi = beta2 * mi + (1.0f - beta2) * g;
        m[i] = mi;

        // write back
        if (master) {
            master[i] = p;
            if constexpr (std::is_same_v<ParamT, half>)
                params[i] = __float2half(p);
            else
                params[i] = __float2bfloat16(p);
        } else {
            params[i] = p;
        }
    }
}

// ---------------------------------------------------------------------------
// Vectorised FP32 Lion — float4, 4 elements / thread
// ---------------------------------------------------------------------------
__global__ void k_lion_vec4_fp32(
        float*        __restrict__ params,
        const float*  __restrict__ grads,
        float*        __restrict__ m,
        size_t  numel4,
        float   lr,
        float   beta1,
        float   beta2,
        float   weight_decay)
{
    const float one_m_b1 = 1.0f - beta1;
    const float one_m_b2 = 1.0f - beta2;

    for (size_t i4 = blockIdx.x * blockDim.x + threadIdx.x;
         i4 < numel4;
         i4 += gridDim.x * blockDim.x)
    {
        size_t b = i4 * 4;
        float4 p4 = *reinterpret_cast<const float4*>(params + b);
        float4 g4 = *reinterpret_cast<const float4*>(grads  + b);
        float4 m4 = *reinterpret_cast<const float4*>(m      + b);

#define LION_STEP(x) \
        { \
            float interp = beta1 * m4.x + one_m_b1 * g4.x; \
            float upd    = (interp > 0.0f) - (interp < 0.0f); \
            p4.x = p4.x - lr * (upd + weight_decay * p4.x); \
            m4.x = beta2 * m4.x + one_m_b2 * g4.x; \
        }

        LION_STEP(x) LION_STEP(y) LION_STEP(z) LION_STEP(w)
#undef LION_STEP

        *reinterpret_cast<float4*>(params + b) = p4;
        *reinterpret_cast<float4*>(m      + b) = m4;
    }
}

// ---------------------------------------------------------------------------
// Vectorised BF16 Lion — bfloat162, 2 elements / thread (Ampere+)
// ---------------------------------------------------------------------------
__global__ void k_lion_vec2_bf16(
        __nv_bfloat16* __restrict__       params,
        float*         __restrict__       master,
        const __nv_bfloat16* __restrict__ grads,
        float*         __restrict__       m,
        size_t  numel2,
        float   lr,
        float   beta1,
        float   beta2,
        float   weight_decay)
{
    const float one_m_b1 = 1.0f - beta1;
    const float one_m_b2 = 1.0f - beta2;

    for (size_t i2 = blockIdx.x * blockDim.x + threadIdx.x;
         i2 < numel2;
         i2 += gridDim.x * blockDim.x)
    {
        size_t b = i2 * 2;
        float g0, g1;
        prec::load2_bf16(grads, b, g0, g1);

        float p0 = master[b],     p1 = master[b + 1];
        float m0 = m[b],          m1 = m[b + 1];

        // Slot 0
        float i0 = beta1 * m0 + one_m_b1 * g0;
        float u0 = (i0 > 0.0f) - (i0 < 0.0f);
        p0 = p0 - lr * (u0 + weight_decay * p0);
        m0 = beta2 * m0 + one_m_b2 * g0;

        // Slot 1
        float i1 = beta1 * m1 + one_m_b1 * g1;
        float u1 = (i1 > 0.0f) - (i1 < 0.0f);
        p1 = p1 - lr * (u1 + weight_decay * p1);
        m1 = beta2 * m1 + one_m_b2 * g1;

        master[b] = p0; master[b + 1] = p1;
        m[b]      = m0; m[b + 1]      = m1;
        prec::store2_bf16(params, b, p0, p1);
    }
}

// ===========================================================================
// LionOptimizer  –  stateful HPC wrapper
// ===========================================================================
class LionOptimizer {
public:
    explicit LionOptimizer(const LionConfig& cfg) : cfg_(cfg) {}
    ~LionOptimizer() { free_state(); }

    LionOptimizer(const LionOptimizer&)            = delete;
    LionOptimizer& operator=(const LionOptimizer&) = delete;

    void init(const TensorView* params, int n,
              float** master = nullptr,
              cudaStream_t stream = 0)
    {
        free_state();
        n_tensors_ = n;
        master_    = master;
        m_         = new float*[n];

        for (int i = 0; i < n; ++i) {
            size_t bytes = params[i].numel * sizeof(float);
            HPC_CUDA_CHECK(cudaMalloc(&m_[i], bytes));
            HPC_CUDA_CHECK(cudaMemsetAsync(m_[i], 0, bytes, stream));
        }
    }

    void step(TensorView* params, const TensorView* grads, int n,
              cudaStream_t stream = 0)
    {
        for (int i = 0; i < n; ++i) {
            size_t numel = params[i].numel;
            int    blk   = hpc_blocks(numel);

            // FP32 vectorised fast path
            if (params[i].dtype == Dtype::FP32 &&
                grads[i].dtype  == Dtype::FP32 &&
                (numel % 4 == 0))
            {
                k_lion_vec4_fp32<<<blk, HPC_BLOCK, 0, stream>>>(
                    static_cast<float*>(params[i].data),
                    static_cast<const float*>(grads[i].data),
                    m_[i], numel / 4,
                    cfg_.lr, cfg_.beta1, cfg_.beta2, cfg_.weight_decay);
                continue;
            }

            // BF16 + master path
            if (params[i].dtype == Dtype::BF16 && master_ && (numel % 2 == 0)) {
                k_lion_vec2_bf16<<<blk, HPC_BLOCK, 0, stream>>>(
                    static_cast<__nv_bfloat16*>(params[i].data),
                    master_[i],
                    static_cast<const __nv_bfloat16*>(grads[i].data),
                    m_[i], numel / 2,
                    cfg_.lr, cfg_.beta1, cfg_.beta2, cfg_.weight_decay);
                continue;
            }

            // Scalar fallback
            switch (params[i].dtype) {
                case Dtype::FP32:
                    k_lion<float, float><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<float*>(params[i].data), nullptr,
                        static_cast<const float*>(grads[i].data),
                        m_[i], numel, cfg_.lr,
                        cfg_.beta1, cfg_.beta2, cfg_.weight_decay);
                    break;
                case Dtype::FP16:
                    k_lion<half, half><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<half*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        static_cast<const half*>(grads[i].data),
                        m_[i], numel, cfg_.lr,
                        cfg_.beta1, cfg_.beta2, cfg_.weight_decay);
                    break;
                case Dtype::BF16:
                    k_lion<__nv_bfloat16, __nv_bfloat16><<<blk, HPC_BLOCK, 0, stream>>>(
                        static_cast<__nv_bfloat16*>(params[i].data),
                        master_ ? master_[i] : nullptr,
                        static_cast<const __nv_bfloat16*>(grads[i].data),
                        m_[i], numel, cfg_.lr,
                        cfg_.beta1, cfg_.beta2, cfg_.weight_decay);
                    break;
            }
        }
        step_++;
    }

    // Lion only has one moment buffer — 33% less memory than Adam
    float**           m_buffers()  { return m_; }
    uint32_t          step_count() const { return step_; }
    LionConfig&       config()       { return cfg_; }
    const LionConfig& config() const { return cfg_; }

private:
    LionConfig cfg_;
    float**    m_         = nullptr;
    float**    master_    = nullptr;
    int        n_tensors_ = 0;
    uint32_t   step_      = 0;

    void free_state() {
        if (!m_) return;
        for (int i = 0; i < n_tensors_; ++i) cudaFree(m_[i]);
        delete[] m_; m_ = nullptr; n_tensors_ = 0;
    }
};

} // namespace hpc_opt

include/hpc_lr_scheduler.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_lr_scheduler.cuh  –  LR schedulers for HPC training
//
// All schedulers are host-side, zero-device-overhead.
// They hold a float& to the optimizer config's lr field and update it in-place.
//
// Schedulers:
//   WarmupCosine      –  linear warmup → cosine decay (standard for large LM)
//   WarmupLinear      –  linear warmup → linear decay (BERT pre-training)
//   WarmupConstant    –  linear warmup → constant (fine-tuning)
//   CyclicLR          –  triangular / triangular2 / exp_range (Smith 2017)
//   OneCycleLR        –  1-cycle policy (fast convergence, Smith & Topin 2019)
//   PolynomialLR      –  polynomial decay with optional warmup
//   ReduceLROnPlateau –  adaptive: reduce on metric stagnation
// =============================================================================
#pragma once

#include <cmath>
#include <vector>
#include <algorithm>
#include <limits>

#ifndef M_PI
#  define M_PI 3.14159265358979323846
#endif

namespace hpc_opt {

class LRScheduler {
public:
    virtual ~LRScheduler() = default;
    virtual float step() = 0;
    virtual float get_lr() const = 0;
};

// ---------------------------------------------------------------------------
// WarmupCosine  (linear warmup + cosine annealing)
//   Steps 0..W:    lr = base * t/W
//   Steps W..T:    lr = eta_min + 0.5*(base-eta_min)*(1+cos(π*(t-W)/(T-W)))
// ---------------------------------------------------------------------------
class WarmupCosineLR : public LRScheduler {
public:
    WarmupCosineLR(float& lr, int warmup, int total, float eta_min = 0.0f)
        : lr_(lr), base_(lr), W_(warmup), T_(total), eta_(eta_min) {}

    float step() override {
        ++t_;
        if (t_ <= W_) {
            lr_ = base_ * static_cast<float>(t_) / static_cast<float>(W_);
        } else {
            float p = static_cast<float>(t_ - W_) / static_cast<float>(T_ - W_);
            lr_ = eta_ + 0.5f * (base_ - eta_) *
                  (1.0f + cosf(static_cast<float>(M_PI) * p));
        }
        return lr_;
    }

    float get_lr() const override { return lr_; }

private:
    float& lr_;
    float  base_, eta_;
    int    W_, T_, t_ = 0;
};

// ---------------------------------------------------------------------------
// WarmupLinear  –  linear warmup then linear decay to eta_min
// ---------------------------------------------------------------------------
class WarmupLinearLR : public LRScheduler {
public:
    WarmupLinearLR(float& lr, int warmup, int total, float eta_min = 0.0f)
        : lr_(lr), base_(lr), W_(warmup), T_(total), eta_(eta_min) {}

    float step() override {
        ++t_;
        if (t_ <= W_) {
            lr_ = base_ * static_cast<float>(t_) / W_;
        } else {
            float p = static_cast<float>(t_ - W_) / (T_ - W_);
            lr_ = base_ - (base_ - eta_) * p;
            lr_ = std::max(lr_, eta_);
        }
        return lr_;
    }

    float get_lr() const override { return lr_; }

private:
    float& lr_;
    float  base_, eta_;
    int    W_, T_, t_ = 0;
};

// ---------------------------------------------------------------------------
// WarmupConstant  –  warmup then hold base_lr
// ---------------------------------------------------------------------------
class WarmupConstantLR : public LRScheduler {
public:
    WarmupConstantLR(float& lr, int warmup)
        : lr_(lr), base_(lr), W_(warmup) {}

    float step() override {
        ++t_;
        if (t_ <= W_) lr_ = base_ * static_cast<float>(t_) / W_;
        return lr_;
    }

    float get_lr() const override { return lr_; }

private:
    float& lr_; float base_; int W_, t_ = 0;
};

// ---------------------------------------------------------------------------
// PolynomialLR
//   lr_t = (base - eta_min) * ((1 - t/T) ^ power) + eta_min
//   Optional warmup prepended.
// ---------------------------------------------------------------------------
class PolynomialLR : public LRScheduler {
public:
    PolynomialLR(float& lr, int total, float power = 1.0f,
                 float eta_min = 0.0f, int warmup = 0)
        : lr_(lr), base_(lr), T_(total), pow_(power),
          eta_(eta_min), W_(warmup) {}

    float step() override {
        ++t_;
        if (t_ <= W_) {
            lr_ = base_ * static_cast<float>(t_) / W_;
        } else {
            int t_adj = t_ - W_;
            int T_adj = T_  - W_;
            float p = static_cast<float>(t_adj) / static_cast<float>(T_adj);
            p = std::min(p, 1.0f);
            lr_ = (base_ - eta_) * powf(1.0f - p, pow_) + eta_;
        }
        return lr_;
    }

    float get_lr() const override { return lr_; }

private:
    float& lr_; float base_, eta_, pow_; int T_, W_, t_ = 0;
};

// ---------------------------------------------------------------------------
// OneCycleLR  (Smith & Topin 2019)
//   Phase 1 [0..pct*T]:  cosine from base/div_factor → base
//   Phase 2 [pct*T..T]:  cosine from base → base/final_div_factor
// ---------------------------------------------------------------------------
class OneCycleLR : public LRScheduler {
public:
    OneCycleLR(float& lr,
               float max_lr,
               int   total_steps,
               float pct_start       = 0.3f,
               float div_factor      = 25.0f,
               float final_div_factor= 1e4f)
        : lr_(lr),
          max_lr_(max_lr),
          base_lr_(max_lr / div_factor),
          min_lr_ (max_lr / final_div_factor),
          T_(total_steps),
          T1_(static_cast<int>(total_steps * pct_start))
    {
        lr_ = base_lr_;
    }

    float step() override {
        ++t_;
        if (t_ <= T1_) {
            float p = static_cast<float>(t_) / T1_;
            lr_ = base_lr_ + 0.5f * (max_lr_ - base_lr_) * (1.0f - cosf(static_cast<float>(M_PI) * p));
        } else {
            int t2 = t_ - T1_, T2 = T_ - T1_;
            float p = static_cast<float>(t2) / T2;
            lr_ = min_lr_ + 0.5f * (max_lr_ - min_lr_) * (1.0f + cosf(static_cast<float>(M_PI) * p));
        }
        return lr_;
    }

    float get_lr() const override { return lr_; }

private:
    float& lr_;
    float  max_lr_, base_lr_, min_lr_;
    int    T_, T1_, t_ = 0;
};

// ---------------------------------------------------------------------------
// CyclicLR  –  triangular / triangular2 / exp_range
// ---------------------------------------------------------------------------
class CyclicLR : public LRScheduler {
public:
    enum class Mode { Triangular, Triangular2, ExpRange };

    CyclicLR(float& lr,
             float base_lr, float max_lr,
             int   step_size_up   = 2000,
             int   step_size_down = -1,
             Mode  mode = Mode::Triangular,
             float gamma = 1.0f)
        : lr_(lr), base_(base_lr), max_(max_lr),
          up_(step_size_up),
          down_(step_size_down < 0 ? step_size_up : step_size_down),
          mode_(mode), gamma_(gamma)
    {
        lr_ = base_lr;
        cycle_size_ = up_ + down_;
    }

    float step() override {
        int pos_in_cycle = t_ % cycle_size_;
        float x;
        if (pos_in_cycle < up_) {
            x = static_cast<float>(pos_in_cycle) / up_;
        } else {
            x = 1.0f - static_cast<float>(pos_in_cycle - up_) / down_;
        }

        float scale = 1.0f;
        int cycle = t_ / cycle_size_;
        switch (mode_) {
            case Mode::Triangular:  scale = 1.0f; break;
            case Mode::Triangular2: scale = 1.0f / powf(2.0f, static_cast<float>(cycle)); break;
            case Mode::ExpRange:    scale = powf(gamma_, static_cast<float>(t_)); break;
        }

        lr_ = base_ + (max_ - base_) * x * scale;
        ++t_;
        return lr_;
    }

    float get_lr() const override { return lr_; }

private:
    float& lr_; float base_, max_, gamma_;
    int    up_, down_, cycle_size_, t_ = 0;
    Mode   mode_;
};

// ---------------------------------------------------------------------------
// ReduceLROnPlateau
// ---------------------------------------------------------------------------
class ReduceLROnPlateau : public LRScheduler {
public:
    ReduceLROnPlateau(float& lr,
                      float  factor    = 0.5f,
                      int    patience  = 5,
                      float  min_lr    = 1e-7f,
                      float  threshold = 1e-4f,
                      bool   maximize  = false)
        : lr_(lr), factor_(factor), patience_(patience),
          min_lr_(min_lr), threshold_(threshold), maximize_(maximize),
          best_(maximize ? -1e30f : 1e30f) {}

    // Call with the monitored metric (val_loss or val_acc)
    float step(float metric) {
        bool improved = maximize_
            ? (metric > best_ + threshold_)
            : (metric < best_ - threshold_);

        if (improved) { best_ = metric; bad_ = 0; }
        else if (++bad_ >= patience_) {
            lr_ = std::max(lr_ * factor_, min_lr_);
            bad_ = 0;
        }
        return lr_;
    }

    float step() override { return lr_; }   // base no-op
    float get_lr() const override { return lr_; }

private:
    float& lr_;
    float  factor_, min_lr_, threshold_, best_;
    int    patience_, bad_ = 0;
    bool   maximize_;
};

} // namespace hpc_opt

include/hpc_optimizer.cuh:
// =============================================================================
// HPC CUDA Optimizer Library
// hpc_optimizer.cuh  –  Unified HPC Optimizer facade
//
// Single include that wires together all optimizers, the comm layer,
// gradient clipper, checkpoint I/O, NVTX profiler, and LR schedulers.
//
// Design goals:
//   • Minimal per-step overhead – one virtual dispatch max (scheduler)
//   • All heavy work deferred to streams; no implicit sync on hot path
//   • Distributed-aware: all_reduce before step; ZeRO-1 optional
//   • Checkpointing on any schedule (every N steps, on signal, etc.)
//
// Typical usage (single GPU, FP32 AdamW):
//   hpc_opt::HPCOptimizer<hpc_opt::AdamOptimizer> opt(
//       hpc_opt::make_adamw_config(3e-4f), stream);
//   opt.init(params, n);
//   for (int s = 0; s < N; ++s) {
//       backward();
//       opt.step(params, grads, n);   // clip + all_reduce + optimizer
//   }
// =============================================================================
#pragma once

#include "hpc_types.h"
#include "hpc_precision.cuh"
#include "hpc_grad_clip.cuh"
#include "hpc_adam.cuh"
#include "hpc_sgd.cuh"
#include "hpc_lamb.cuh"
#include "hpc_lion.cuh"
#include "hpc_comm.cuh"
#include "hpc_checkpoint.cuh"
#include "hpc_profiler.cuh"
#include "hpc_lr_scheduler.cuh"

#include <memory>
#include <functional>
#include <string>
#include <cstdio>

namespace hpc_opt {

// ---------------------------------------------------------------------------
// Config factory helpers
// ---------------------------------------------------------------------------
inline AdamConfig make_adam_config(float lr = 1e-3f, float wd = 0.0f) {
    AdamConfig c; c.lr = lr; c.weight_decay = wd; return c;
}
inline AdamConfig make_adamw_config(float lr = 3e-4f, float wd = 1e-2f) {
    AdamConfig c; c.lr = lr; c.weight_decay = wd; return c;
}
inline SGDConfig make_sgd_config(float lr = 1e-2f, float mom = 0.9f) {
    SGDConfig c; c.lr = lr; c.momentum = mom; return c;
}
inline LAMBConfig make_lamb_config(float lr = 1e-3f, float wd = 1e-2f) {
    LAMBConfig c; c.lr = lr; c.weight_decay = wd; return c;
}
inline LionConfig make_lion_config(float lr = 1e-4f, float wd = 1e-2f) {
    LionConfig c; c.lr = lr; c.weight_decay = wd; return c;
}

// ---------------------------------------------------------------------------
// Optimizer type enum (for factory / display)
// ---------------------------------------------------------------------------
enum class OptimizerKind { Adam, AdamW, SGD, LAMB, Lion };

inline const char* optimizer_name(OptimizerKind k) {
    switch(k) {
        case OptimizerKind::Adam:  return "Adam";
        case OptimizerKind::AdamW: return "AdamW";
        case OptimizerKind::SGD:   return "SGD";
        case OptimizerKind::LAMB:  return "LAMB";
        case OptimizerKind::Lion:  return "Lion";
    }
    return "Unknown";
}

// ===========================================================================
// HPCOptimizer<BackendT>
//   BackendT is one of: AdamOptimizer, SGDOptimizer, LAMBOptimizer, LionOptimizer
// ===========================================================================
template<typename BackendT, typename ConfigT>
class HPCOptimizer {
public:
    // -----------------------------------------------------------------------
    // Construction
    // -----------------------------------------------------------------------
    HPCOptimizer(const ConfigT& cfg,
                 cudaStream_t   stream      = 0,
                 CommContext*   comm        = nullptr,   // nullptr = single GPU
                 float**        master_fp32 = nullptr)  // for mixed-precision
        : backend_(cfg), stream_(stream), comm_(comm), master_fp32_(master_fp32)
    {}

    ~HPCOptimizer() = default;

    HPCOptimizer(const HPCOptimizer&)            = delete;
    HPCOptimizer& operator=(const HPCOptimizer&) = delete;

    // -----------------------------------------------------------------------
    // init  –  allocate optimizer state; must be called once before step().
    // -----------------------------------------------------------------------
    void init(const TensorView* params, int n) {
        n_tensors_  = n;
        params_ref_ = params;

        backend_.init(params, n, master_fp32_, stream_);

        // Cache per-tensor numel for checkpoint helpers
        numel_list_.resize(n);
        for (int i = 0; i < n; ++i) numel_list_[i] = params[i].numel;

        HPC_CUDA_CHECK(cudaStreamSynchronize(stream_));
    }

    // -----------------------------------------------------------------------
    // step  –  one full optimiser step:
    //   (1) optional grad clipping
    //   (2) NCCL all-reduce (if distributed)
    //   (3) backend optimizer kernel
    //   (4) optional LR schedule advance
    //   (5) optional checkpoint
    // -----------------------------------------------------------------------
    void step(TensorView* params, TensorView* grads, int n) {
        HPC_RANGE_SCOPED("hpc_opt::step", 0xFF2196F3);

        // ---- Gradient clipping ----
        if (clip_enabled_) {
            HPC_RANGE_PUSH("grad_clip", 0xFFFFC107);
            clipper_.clip(grads, n, clip_cfg_, stats_, stream_,
                          (comm_ && comm_->initialized()) ? nullptr : nullptr);
            HPC_RANGE_POP();
        }

        // ---- All-reduce gradients across GPUs ----
        if (comm_ && comm_->initialized() && comm_->world_size() > 1) {
            HPC_RANGE_PUSH("nccl_allreduce", 0xFF4CAF50);
            comm_->all_reduce_grads(grads, n, /*fp16_compress=*/fp16_comm_, stream_);
            HPC_RANGE_POP();
        }

        // ---- Optimizer kernel ----
        {
            HPC_RANGE_PUSH("optimizer_kernel", 0xFF2196F3);
            backend_.step(params, grads, n, stream_);
            HPC_RANGE_POP();
        }

        // ---- Update stats ----
        stats_.step++;
        stats_.last_lr = current_lr();

        // ---- LR scheduler ----
        if (scheduler_) scheduler_->step();

        // ---- Periodic checkpoint ----
        if (ckpt_every_ > 0 && ckpt_rank0_path_.size() > 0
            && stats_.step % ckpt_every_ == 0)
        {
            save_checkpoint(ckpt_rank0_path_
                            + "/ckpt_step"
                            + std::to_string(stats_.step)
                            + ".bin");
        }
    }

    // -----------------------------------------------------------------------
    // Gradient clip config
    // -----------------------------------------------------------------------
    void enable_clipping(float max_norm = 1.0f, bool fp16_comm = true) {
        clip_enabled_    = true;
        clip_cfg_.max_norm = max_norm;
        fp16_comm_       = fp16_comm;
    }

    // -----------------------------------------------------------------------
    // LR scheduler
    // -----------------------------------------------------------------------
    void set_scheduler(std::unique_ptr<LRScheduler> s) {
        scheduler_ = std::move(s);
    }

    LRScheduler* lr_scheduler() { return scheduler_.get(); }

    // -----------------------------------------------------------------------
    // Checkpoint
    // -----------------------------------------------------------------------
    void set_checkpoint_dir(const std::string& dir, int every_n_steps) {
        ckpt_rank0_path_ = dir;
        ckpt_every_      = every_n_steps;
    }

    void save_checkpoint(const std::string& path) {
        int rank = comm_ ? comm_->rank() : 0;
        CheckpointIO::save(path,
                           backend_.m_buffers(),
                           numel_list_.data(),
                           n_tensors_,
                           n_tensors_,
                           stats_.step,
                           &backend_.config(),
                           sizeof(backend_.config()),
                           rank);
    }

    uint32_t load_checkpoint(const std::string& path) {
        uint32_t s = CheckpointIO::load(path,
                                        backend_.m_buffers(),
                                        numel_list_.data(),
                                        n_tensors_,
                                        &backend_.config(),
                                        sizeof(backend_.config()),
                                        stream_);
        stats_.step = s;
        return s;
    }

    // -----------------------------------------------------------------------
    // Accessors
    // -----------------------------------------------------------------------
    float          current_lr() const { return backend_.config().lr; }
    uint32_t       step_count() const { return stats_.step; }
    OptimizerStats& stats()           { return stats_; }
    BackendT&       backend()         { return backend_; }
    ConfigT&        config()          { return backend_.config(); }

    void zero_grad(TensorView* grads, int n) {
        for (int i = 0; i < n; ++i) {
            HPC_CUDA_CHECK(cudaMemsetAsync(grads[i].data, 0,
                                           grads[i].byte_size(), stream_));
        }
    }

    // Print a one-line status (rank-0 only)
    void log_step(int step, float loss = -1.0f) const {
        bool root = !comm_ || comm_->is_root();
        if (!root) return;

        if (loss >= 0.0f) {
            fprintf(stdout,
                "[opt] step=%-6d  lr=%.2e  loss=%.4f  "
                "grad_norm=%.3f→%.3f  skipped=%u\n",
                step, current_lr(), loss,
                stats_.grad_norm_before, stats_.grad_norm_after,
                stats_.skipped_steps);
        } else {
            fprintf(stdout,
                "[opt] step=%-6d  lr=%.2e  "
                "grad_norm=%.3f→%.3f  skipped=%u\n",
                step, current_lr(),
                stats_.grad_norm_before, stats_.grad_norm_after,
                stats_.skipped_steps);
        }
    }

private:
    BackendT       backend_;
    cudaStream_t   stream_       = nullptr;
    CommContext*   comm_         = nullptr;
    float**        master_fp32_  = nullptr;
    int            n_tensors_    = 0;
    const TensorView* params_ref_= nullptr;

    GradClipper    clipper_;
    GradClipConfig clip_cfg_;
    bool           clip_enabled_ = false;
    bool           fp16_comm_    = true;

    OptimizerStats stats_{};

    std::unique_ptr<LRScheduler> scheduler_;

    std::string  ckpt_rank0_path_;
    int          ckpt_every_ = 0;

    std::vector<size_t> numel_list_;
};

